INSERT INTO "memory" VALUES('pinned_toolchain','Rust 1.96.0 pinned by rust-toolchain.toml at repo root.','Use plain cargo/rustc; rust-toolchain.toml auto-selects 1.96.0 on any host. Linux cloud sandbox provisions via rustup (rustup show); local dev via Nix flake. No absolute toolchain path.','2026-06-06 02:23:59');
INSERT INTO "memory" VALUES('python_tooling','Use uv for Python/music21/Polars/corpus tooling.','Do not hand-roll venv setup.','2026-06-06 01:33:56');
INSERT INTO "memory" VALUES('abc_reference_repo','/Users/rodox/dev/abc','Use as parser-policy/test/prover reference only; do not copy whole parser.','2026-06-06 06:01:44');
INSERT INTO "memory" VALUES('generated_artifacts_policy','Keep generated corpus XML/parquet/jsonl/reports under docs/untracked/.','Do not commit generated corpus artifacts unless explicitly requested.','2026-06-06 01:33:56');
INSERT INTO "memory" VALUES('formatter_lsp_gate','Formatter (croma fmt + --auto-fix) is UN-GATED and proven (2026-06-15); LSP still gated.','croma fmt is idempotent + lossless over the full 10k corpus (corpus_proof + prove_fmt_lossless.py, 0 violations); see docs/formatter.md. LSP awaits comparable evidence; parser/corpus work stays its priority.','2026-06-15 18:48:56');
INSERT INTO "memory" VALUES('croma_core_crates_io','Keep croma-core crates.io-compatible.','Avoid path-only/local runtime assumptions in library code.','2026-06-06 01:33:56');
INSERT INTO "memory" VALUES('dev_environments','Two supported: Linux cloud sandbox (rustup + uv) and local Nix flake.','Build/validate from repo root: uv sync; cargo build -p croma-cli; cargo test --workspace. See docs/development-environment.md. Corpus roots are external; set ABC_ROOT/REF_ROOT per docs/testing/corpus-reproducibility.md.','2026-06-06 02:23:59');
INSERT INTO "memory" VALUES('phase_10k_outcome','Bar marker in w:/s: advances to next bar at block boundary and for consecutive markers; hyphen after space/hyphen holds a blank note (ABC 2.1 section 5.1).','Direct lyric rows 89->75; remaining 75 in tune_006403/001361/002325/006565 are downstream of measure-structure/overlay diffs, not lyric bugs.','2026-06-06 06:01:54');
INSERT INTO "memory" VALUES('parser_bug_backlog','Active parser/model/export backlog is empty as of phase-38-empty-backlog.','Phase 38 fixed nested tuplets, bare-grace slurs, overlay voice numbering, lyric syllabic export/comparison, +: lyric continuation splitting, orphan hyphen filtering with valid cross-block preservation, and overlay lyric/symbol ABC writer alignment. docs/parser-backlog.md is updated so stale OPEN items are not active. Final 10k compare: 9935 exports, 8898 matches, 1037 mismatches, 161725 rows; final ABC roundtrip: 9933 in scope, 0 structural diffs.','2026-06-12 18:49:30');
INSERT INTO "memory" VALUES('next_target','After phase 54, continue from docs/untracked/phase-54-divergence-triage/full-10k/mismatches-after-drops.parquet and report-after-drops.json. Phase 54 cleared pure measure_alignment single-category files and ended at structural_matches=9270, structural_mismatches=318, dropped_files=347, mismatch_rows=5764. Remaining content-category files are known keeps/deferred policy calls: tune_015465/tune_009575/tune_009205/tune_009207/tune_012357 broken-rhythm policy; tune_001026/tune_012962 boundary-grace placement; tune_009630/tune_011164/tune_013148/tune_007120 empty-bar/harmony-only collapse; tune_005539 whitespace-colon; tune_011865 empty-bar policy. Next structural candidates excluding known keeps: tune_014512, tune_015363, tune_015366, tune_002101, tune_002102, tune_002103. Dispatch one fresh investigator per file unless user explicitly approves a narrow regex/XML-verified bulk exception.','Phase 54 added 129 dropped.csv rows and a TRIAGE.md note for a user-approved forced-4/4 bulk exception. No croma parser/export changes were made; no re-export was needed. The forced-4/4 bulk path requires original ABC regex/token verification plus MusicXML checks and is fail-closed.','2026-06-14 15:14:39');
