INSERT INTO "phase" VALUES('phase-9','codex/phase-9-cli-corpus-gate','complete',NULL,NULL,NULL,'CLI/corpus smoke gate and 66-failure evidence review','mixed: one Croma bug fixed; rest malformed/reference artifacts','10k corpus smoke gate rerun: 9935 successes, 65 failures, 0 panics/hard errors/timeouts after fixing body V: same-line music tail.','Move to full 10k music21 structural comparison.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10','codex/phase-10-full-music21-compare','merged',11,NULL,NULL,'Full 10k music21 structural comparison','comparison baseline','Croma XML importability bugs addressed; 10000 attempted, 9935 exports, 0 music21 import failures, 1335 matches, 8600 mismatches.','Use mismatch categories to choose focused parser fixes.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10a','codex/phase-10a-mismatch-root-causes','merged',12,NULL,'7d7ab46','Polars/root-cause triage','triage/evidence','Identified major clusters: V: voices collapsed, leading first-body barline, tuplet/broken drift, grace/key policy, chord/tie residual alignment, inline state drift, hidden rests.','Fix leading first-measure barline policy first.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10b','codex/phase-10b-leading-barline-policy','merged',13,NULL,'41f5c39','Leading first-body barline policy','Croma bug fixed with known policy edge cases','Leading |, [|, |:, ||, |], liberal first-body barlines no longer create empty measure 1; targeted subset improved sharply.','Define liberal combined barline spellings.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10c','codex/phase-10c-liberal-barlines','merged',14,NULL,'accf7dc','Liberal combined barlines','Croma policy fix','Defined ||:, [|:, :||, :|], :||:, :|:, ::, |::, ::| behavior; full 10k improved to 2897 matches / 7038 mismatches.','Small repeat-policy classification follow-up.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10d','codex/phase-10d-repeat-policy-classification','merged',15,NULL,'d26b318','Repeat policy tests/classification','policy/tests','Added Phase 10-d repeat policy tests after Phase 10-c; details are in PR #15/local reports if needed.','Improve comparison tooling throughput and queryability.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10e','codex/phase-10e-polars-parallel-comparison-tools','merged',16,NULL,'f22a9d1','Parallel music21 + Polars comparison tooling','tooling enhancement','Added jobs/chunk/progress/component/file filters, normalized fact/comparison/mismatch tables, summaries, baseline delta support. Full 10k report-only run took 28.912s with jobs=16.','Use Polars evidence to select focused parser fixes.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10f','codex/phase-10f-polars-guided-parser-fix','merged',17,NULL,'2fbfae2','Cross-bar tie propagation','Croma bug fixed','Legal same-pitch ties across barlines no longer finalize before resolution. Target tie rows 88 -> 0; full tie rows 3398 -> 671.','Text/direction leakage or residual tie mixed cases.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10g','codex/phase-10g-text-direction-leakage','merged',18,'https://github.com/ro-ag/croma/pull/18','640c7a6','Malformed unprefixed quoted chord strings','Croma MusicXML export bug fixed','Strings like "(A7)" and "C/" export as words instead of fake harmony; valid chord symbols still export as harmony. Full mismatch rows -5663.','Body w: lyric alignment/control mismatches.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10h','codex/phase-10h-lyric-alignment-controls','merged',19,NULL,'ce6c160','Lyric hyphen control MusicXML export','Croma MusicXML export bug fixed','ABC lyric - controls no longer export as standalone sung text; escaped literal hyphens remain text. Full mismatch rows -66232; lyric rows 28985 -> 628.','Residual _ melisma/hold lyric alignment, especially tune_000509.abc.','2026-06-06 01:33:56');
INSERT INTO "phase" VALUES('phase-10i','codex/phase-10i-lyric-melisma-hold','merged',20,'https://github.com/ro-ag/croma/pull/20','51440fb','NBSP lyric tokenization plus empty-extender comparison for _ melisma holds','Croma bug plus comparison harness bug fixed','Fixed tune_000509-style lyric _ melisma/hold evidence: Croma no longer treats U+00A0 inside body w: lyrics as a separator, and comparison tooling preserves empty MusicXML lyric extender slots. Target direct lyric rows reduced; no targeted regressions.','Remaining direct lyric rows: 89 rows in 7 files, likely lyric cursor/reference-policy behavior; triage separately.','2026-06-06 01:46:30');
INSERT INTO "phase" VALUES('testbed-reproducibility','codex/testbed-reproducibility-recipe','complete',NULL,NULL,NULL,'Corpus/testbed recreation recipe','documentation/infrastructure','Added a committed recipe for recreating full 10k exports, report-only Music21/Polars comparisons, optional large table artifacts, targeted corpus selection, targeted comparisons, validation queries, and progress tracker restore/query/export workflow. Updated corpus inventory to the local trd_obsolete input/reference roots.','Use the recipe before the next parser phase; then triage the remaining 89 direct lyric rows in 7 files.','2026-06-06 02:01:00');
INSERT INTO "phase" VALUES('linux-sandbox-env','codex/phase-10j-linux-sandbox-env','complete',NULL,NULL,NULL,'Port dev-environment and corpus reproducibility docs from macOS-only paths to a portable Linux cloud sandbox + Nix flake setup; provision Rust 1.96.0 (rustup) and uv Python env','tooling/docs','Rewrote docs/development-environment.md for Linux cloud sandbox (rustup) and local Nix flake; made docs/testing/corpus-reproducibility.md environment-agnostic (ABC_ROOT/REF_ROOT vars, rust-toolchain.toml instead of absolute toolchain path); added provenance note to corpus-inventory.md; updated pinned_toolchain memory and added dev_environments memory. Built env: cargo build -p croma-cli OK, uv sync OK; cargo test --workspace green (cli 18, croma-core 145, croma-fmt 1).','Provision the external 10k corpus (ABC_ROOT/REF_ROOT) into the sandbox, then triage the residual 89 direct lyric rows in 7 files per phase-10i.','2026-06-06 02:24:17');
INSERT INTO "phase" VALUES('bootstrap-hardening','codex/bootstrap-hardening','complete',NULL,NULL,NULL,'Session bootstrap fail-fast behavior and uv fallback','tooling fix','Hardened tools/session_bootstrap.sh with fail-fast behavior, uv/python3 progress restore fallback, optional verified Git LFS ABC corpus cache import, Zenodo fallback provisioning, and explicit partial corpus status.','Continue Phase 10 parser work after provisioning ABC corpus and reference MusicXML; residual lyric policy triage remains next.','2026-06-06 04:35:22');
INSERT INTO "phase" VALUES('phase-10k','work/phase-10k-lyric-bar-marker','merged',25,'https://github.com/ro-ag/croma/pull/25',NULL,'Residual 89 direct lyric rows in 7 files (lyric cursor/bar-marker policy)','Croma bug fixed (two spec violations); residual rows justified as measure-model/overlay downstream artifacts','Fixed two ABC 2.1 section 5.1 violations: (1) a w:/s: bar marker now advances to the next bar at a block boundary and for consecutive markers instead of being ignored against the previous block note; (2) a hyphen preceded by a space or another hyphen now holds a blank note instead of exporting a literal dash. Direct lyric rows 89->75 across the full 10k; 3 files reach 100% lyric match and +7 files now fully match structurally with no category regressions. Remaining 75 rows in 4 files are downstream of measure-structure (empty leading harmony measure, cut-time grouping, inline meter-change empty measures) or voice-overlay divergences, which the positional comparison cannot align; lyric-to-note alignment is itself correct.','Triage measure-model differences: leading bare-harmony empty measure (tune_006403) and inline meter-change spurious empty measures (tune_002325); both are high-value measure_alignment/barline targets.','2026-06-06 06:34:21');
INSERT INTO "phase" VALUES('phase-10l','work/phase-10l-inline-field-barline','merged',NULL,NULL,NULL,'Inline information field after a barline mis-parsed as a liberal combined barline','Croma parser bug fixed','Fixed a parser bug where a barline immediately followed by an inline field (e.g. |[M:3/8], |[K:D]) swallowed the [ into a liberal |[ barline, dropping the field and inserting a spurious empty measure plus cascading garbage. The barline scan now stops before a [ that begins an inline field. Full 10k report-only mismatch rows drop 3,577,076 -> 3,536,841 (-40,235) with every category improved and none regressed; affects 62 corpus files. tune_002325 fully resolves (11 measures matching reference, 100 percent lyric match).','Apply inline [K:]/[M:]/[L:] changes (parsed but not yet applied): 377 files use inline key changes, 135 use inline meter; route them to the existing key/meter/unit change handlers and emit mid-tune key signatures.','2026-06-06 06:34:21');
INSERT INTO "phase" VALUES('phase-10m','work/phase-10m-inline-field-apply','merged',NULL,NULL,NULL,'Inline [K:]/[M:]/[L:] information fields parsed but never applied mid-tune','Croma parser bug fixed','Routed inline [M:]/[K:]/[L:] fields to the existing meter/key/unit change handlers so a mid-line change affects subsequent notes (accidentals, durations, meter). Hardened key tonic parsing so a clef shorthand or property token (bass, clef=bass) that happens to start with a note letter is no longer misread as a key change, and a clef-only inline [K:] leaves the signature untouched. Full 10k mismatch rows drop 3,536,841 -> 3,524,300 (-12,541): duration -7,838, accidental -2,499, measure_alignment -2,011, plus +30 fully-matching files and no category regressions.','Emit mid-tune <key>/<time> attributes in the MusicXML writer (currently applied to notes but not declared); then triage the remaining large missing_in_croma/extra_in_croma categories.','2026-06-06 07:01:17');
INSERT INTO "phase" VALUES('phase-10n','work/phase-10n-multipart-export','merged',NULL,NULL,NULL,'Single combined MusicXML part for multi-voice tunes vs one part per voice in abc2xml','Croma export model gap fixed (multi-voice multipart)','build_score_model now emits one MusicXML part per ABC voice (single score-partwise document, all parts), matching abc2xml/music21 and Finale-style export. Single-voice tunes are unchanged. Full 10k mismatch rows drop 3,524,300 -> 393,045 (-3,131,255, -89 percent): missing_in_croma -1,668,240, extra_in_croma -1,478,486, measure_alignment -10,957, slur -1,574, metadata -634, +29 fully-matching files. Correct part alignment EXPOSES pre-existing per-note mismatches previously hidden in the missing/extra bucket: octave +21,940 (clef octave transposition like clef=treble-8 not applied), duration +3,054, pitch +1,469, accidental +1,307. These are now visible and become the next targets.','Apply clef octave transposition (clef=treble-8/+8, octave=N) to voice note octaves to match abc2xml (octave +21,940 exposed by multipart).','2026-06-06 16:46:07');
INSERT INTO "phase" VALUES('phase-10o','work/phase-10o-clef-octave','merged',NULL,NULL,NULL,'Clef octave transposition (clef=treble-8 etc.) not applied; bare V: switch clobbered header voice properties','Croma export bug fixed','Apply the clef octave suffix (clef=treble-8/+8, +/-15) and octave= property as a per-voice octave shift on note octaves, and emit a matching clef-octave-change. Also fixed a pre-existing bug where a bare body V: switch overwrote a voices header-defined properties (clef/name/etc.) with empty values; properties now merge so each voice keeps its clef. Full 10k octave mismatches drop 29,970 -> 12,347 (-17,623), total rows 393,045 -> 375,387 (-17,658), no category regressions.','Triage remaining duration (27,664), measure_alignment (21,310), pitch (18,993), and the residual missing/extra (261k) categories.','2026-06-06 17:25:23');
INSERT INTO "phase" VALUES('phase-10p','work/phase-10p-direction-cleanup','merged',NULL,NULL,NULL,'W: post-tune words emitted as in-measure directions and duplicated per part','Croma export corrected to ABC + MusicXML specs','Per ABC 2.1 (W: = words printed after the tune) and MusicXML (page-level text = score-header <credit>), W: post-tune verses now export as <credit><credit-words> instead of in-measure <words> directions, and empty W: lines are skipped. Score-level directions (tempo, %% directives) are emitted once in the first part instead of once per voice-part. Full 10k structural matches +173 (3,153 -> 3,326), mismatch rows 375,387 -> 353,827 (-21,560): extra_in_croma -20,983, direction -646, with +69 missing_in_croma edge. abc2xml is only a baseline; this follows the ABC and MusicXML specs.','Map ABC decorations (!fermata!, articulations, ornaments) to MusicXML notation elements instead of <words> directions; then duration/pitch residuals.','2026-06-06 22:40:16');
INSERT INTO "phase" VALUES('phase-10q','work/phase-10q-decoration-notations','merged',NULL,NULL,NULL,'ABC decorations (fermata, articulations) emitted as <words> directions instead of notation elements','Croma export corrected to MusicXML notation categories','Map ABC !decorations! to the correct MusicXML <notations> category per the ABC 2.1 decoration list and MusicXML schema: fermata/invertedfermata -> <fermata>, staccato/accent/tenuto/wedge/marcato/breath -> <articulations>, trill/mordent/turn etc -> <ornaments>, upbow/downbow/open/thumb/snap -> <technical>. Previously only staccato/trill were handled (and staccato was wrongly placed in <ornaments>); everything else fell through to <words>. Full 10k structural matches +16 (3,326 -> 3,342), mismatch rows 353,827 -> 346,454 (-7,373): extra_in_croma -7,318, direction -85. fermata is the most common decoration in the corpus (6,669).','Triage duration (27,664), measure_alignment (21,310), pitch (18,993), octave (12,347), and residual missing/extra; then write the Phase 10 closure report.','2026-06-07 00:04:28');
INSERT INTO "phase" VALUES('phase-10r','work/phase-10r-staccato-chord-length','merged',NULL,NULL,NULL,'Staccato chord .[...] mis-parsed as a dotted barline, splitting the chord and dropping its length','Croma parser bug fixed','parse_dot treated [ as a barline character, so a staccato chord like .[CE]2 became a dotted barline plus separate notes with the length suffix lost. A dotted barline now starts only before | or :, so .[...] parses as a staccato chord that keeps its length. Full 10k mismatch rows 346,454 -> 329,547 (-16,907): extra_in_croma -8,744, missing_in_croma -6,475, with nearly every category improved (the chord split had cascaded into note/pitch/duration counts). Affects 94 occurrences in 20 files plus downstream.','Triage remaining duration (27,172), measure_alignment (20,895), pitch (18,707), octave (12,186), and residual missing/extra.','2026-06-07 00:59:47');
INSERT INTO "phase" VALUES('phase-10s','work/phase-10s-chord-barline','merged',NULL,NULL,NULL,'A chord adjacent to a barline (|[G2C,2], ][) mis-parsed as a liberal combined barline, splitting chords and over-fragmenting measures','Croma parser bug fixed','[ is a barline character (for [|, [::]), so the greedy barline scanner swallowed the [ that opens a chord right after a bar (|[G2C,2]) or between adjacent chords (][). The chord was split into separate notes and spurious measure boundaries were inserted. The scanner now stops at a [ that appears mid-scan and is not part of [|, so chords adjacent to barlines stay intact. Also fixed an infinite-loop edge for [] / [: by restoring the original parse_left_bracket guard. Full 10k mismatch rows 329,547 -> 231,594 (-97,953, -30 percent): extra_in_croma -45,105, missing_in_croma -31,260, with almost every category improving (chord splitting had cascaded into note/pitch/duration/measure counts). Affects 317 chord-heavy files.','Triage remaining missing/extra (141k), duration (21,965), measure_alignment (15,295), pitch (14,054), and the %%staves brace/paren grouping (multi-staff parts).','2026-06-07 04:55:49');
INSERT INTO "phase" VALUES('phase-10t','work/phase-10t-unclosed-decoration','merged',34,'https://github.com/ro-ag/croma/pull/34',NULL,'An unclosed ! decoration swallowed the following notes as its name','Croma parser bug fixed','parse_decoration scanned an unclosed ! up to whitespace or a barline, so a stray ! before notes (e.g. !f2e2f2, a deprecated line-break or typo) consumed those notes as the decoration name and dropped them. The recovery now keeps only the ! as malformed and rewinds so the following notes parse normally, matching abc2xml. Full 10k mismatch rows 231,594 -> 229,329 (-2,265): missing_in_croma -1,427, with nearly every category improving and no regression. tune_004513/004512 recover 3 dropped notes each (95 -> 98).','Triage the %%staves brace/paren grouping (multi-staff parts, biggest remaining systematic gap) and remaining measure-structure offsets.','2026-06-07 07:37:32');
INSERT INTO "phase" VALUES('phase-10-closure','work/phase-10-closure','merged',NULL,NULL,NULL,'Phase 10 corpus-driven parser/export hardening closure report','Phase 10 closure','Phase 10 closed: full 10k mismatch rows 3,578,140 -> 229,329 (-93.6 percent), structural matches 3,086 -> 3,396 (+310), across 10 merged spec-grounded fixes (PR #25-#34). No corpus panics, hard errors, or MusicXML import failures; 65 export failures are no-music/empty-body ABC documents. Remaining mismatches classified as abc2xml reference artifacts (Croma spec-correct), the %%staves () grouping deferred model gap (~8 files), small per-file measure issues, and positional comparison cascade. Closure report at docs/progress/phase-10-closure-report.md.','Implement %%staves () grouping (merge grouped voices into one multi-voice part); then deferred MusicXML writer refinements, then formatter/LSP per the roadmap.','2026-06-07 07:41:38');
INSERT INTO "phase" VALUES('phase-11a','work/phase-11a-staves-paren-grouping','merged',36,NULL,NULL,'%%staves () grouping ignored (one part per voice) and %%staves emitted as a words direction','Croma model gap fixed (multi-staff grouping)','Recognize %%staves like %%score and honour parenthesis grouping: voices inside a () group merge into one multi-voice part (overlay), while [] brackets and {} braces keep one part per voice. %%staves is now a parsed score directive instead of a preserved directive, so it is no longer emitted as a <words> direction. Full 10k structural matches +105 (3,396 -> 3,501), mismatch rows 229,329 -> 214,560 (-14,769): extra_in_croma -7,700, missing_in_croma -6,666, metadata -7, no regressions. tune_003557 now matches abc2xml part structure (3 parts).','Deferred MusicXML writer refinements (mid-tune <key>/<time>), then formatter/LSP per the roadmap; remaining residual is abc2xml reference artifacts and small per-file measure issues.','2026-06-07 08:03:19');
INSERT INTO "phase" VALUES('phase-11b','work/phase-11b-tempo-metronome','merged',37,'https://github.com/ro-ag/croma/pull/37','2e3256f','Q: tempo field exported as plain <words> (TextExpression) instead of a MusicXML metronome direction','Croma export gap fixed (spec-correct)','Q: tempo fields were emitted as <words>, so music21 read a generic TextExpression instead of a MetronomeMark. Now parse Q: into a tempo model and emit a <metronome> direction (beat-unit/beat-unit-dot/per-minute + sound tempo) matching ABC 2.1 3.1.8 and the MusicXML spec. Full 10k: structural matches 3,501 -> 5,263 (+1,762 files); mismatch rows 214,560 -> 211,589 (-2,971); direction 5,016 -> 2,059 (-2,957), no category regressions. Residual direction rows are abc2xml guessing bpm from free text / Italian tempo-name lookup (beyond spec) — Croma is spec-correct to keep them as words.','Triage duration (21,635), measure_alignment (14,998), pitch (13,776), octave (9,921), accidental (6,366) for systematic Croma bugs; remaining direction residual is reference artifact.','2026-06-07 20:03:13');
INSERT INTO "phase" VALUES('phase-11c','work/phase-11c-parallel-harness','merged',38,NULL,'8e340c7','Corpus tooling ran the export serially and the comparison on all 16 cores','Local tooling performance','corpus_harness.py export loop was fully serial and music21_polars_corpus_compare.py used all CPU cores. Parallelized the harness export over a ProcessPoolExecutor and capped both tools at cores-1 (host CPU minus 1) to keep the main process healthy. Output is byte-identical to serial (verified on 500 files, order preserved, resume intact); export speedup 3.6-7.2x. Local-only dev tooling, not in CI.','Fix the two confirmed accidental Croma bugs: inline [K:] key change leaking across all voices (should scope to current voice), and tie-across-barline losing the tied accidental (reset_measure_accidentals ignores pending_tie).','2026-06-07 20:22:53');
INSERT INTO "phase" VALUES('phase-11d','work/phase-11d-accidental-propagation','merged',39,NULL,'2f12fad','accidental category: inline [K:] leaking across voices and tie-across-barline losing the tied accidental','Croma parser bugs fixed (spec-correct)','Two confirmed accidental bugs. (A) an inline [K:] inside one voice line was applied to all voices, wiping their key accidentals; now scoped to the current voice only (ABC 2.1 sec 7), header K: unchanged. (B) a tie crossing a barline lost its accidental because reset_measure_accidentals cleared it and the stop note re-resolved from the key; now the tied pitch is preserved across the barline reset (ABC 2.1 sec 4.20). Full 10k: matches 5,263 -> 5,269 (+6); mismatch rows 211,589 -> 211,425 (-164); accidental 6,366 -> 6,215 (-151), slur -13, no regressions. Residual accidental rows are abc2xml courtesy naturals (beyond ABC 2.1 sec 4.2) — Croma is spec-correct.','Triage barline (5,846; 353 single-category files) and measure_alignment (14,998; 257 single-category) for the next systematic Croma bug; duration/pitch/octave remain.','2026-06-07 20:41:34');
INSERT INTO "phase" VALUES('phase-11e','work/phase-11e-repeat-start-placement','merged',40,NULL,'19abba9','barline category: repeat-start |: placed one measure too early (or dropped), and |] final barline dropped when followed by |','Croma parser/export bugs fixed (spec-correct)','Repeat-start |: that follows content was stored on the preceding measure and emitted as its left forward-repeat instead of the left barline of the measure beginning the repeat (ABC 2.1 sec 6). Fixed by deferring a trailing RepeatStart to the next measure via the existing pending_left_repeat path; leading |: unchanged. Also fixed |]| where the greedy barline tokenizer ate |] (Final) into a Liberal run — parse_barline now breaks after ] . Full 10k: matches 5,269 -> 5,556 (+287); mismatch rows 211,425 -> 210,106 (-1,319); barline 5,846 -> 3,341 (-2,505). Other categories rose from positional-cascade exposure (corrected measure boundaries realign the positional comparison). Per-file check: 288 files gained perfect match, 1 regressed by a single barline row (tune_010088, a 4-voice tune with an empty trailing |] measure).','Follow up tune_010088 multi-voice empty trailing measure final-barline edge; then research the remaining structural mismatch landscape (duration, pitch, measure_alignment, missing/extra cascades).','2026-06-07 23:56:14');
INSERT INTO "phase" VALUES('phase-11f','work/phase-11f-shorthand-decorations','merged',41,NULL,'13db6ef','extra_in_croma direction: ABC shorthand decorations emitted as <words> instead of MusicXML notations','Croma export bug fixed (spec-correct)','ABC 2.1 sec 4.14 single-char shorthand decorations (H fermata, T trill, u/v bowing, M/P mordents, S segno, O coda, L accent, ~ roll) and U:-defined symbols were stored as the raw char and exported as <words>, since the exporter only matched canonical long names (phase-10q). Now normalized to canonical names at parse time so they map through the existing notation/symbol/articulation path; ~ (roll, no clean MusicXML equivalent, abc2xml emits nothing) is suppressed (no words, no diagnostic). Full 10k: matches 5,556 -> 6,364 (+808); mismatch rows 210,106 -> 204,096 (-6,010); extra_in_croma -5,630, direction -585; zero match->mismatch regressions. Research-confirmed largest actionable clean signal.','Fix grace-note length modifiers (grace <type> from count only, ignores written length) for the duration category; then harmony chord-symbol diffs. Remaining missing/extra and accidental are mostly abc2xml reference artifacts (phantom measures, hardcoded L:1/8, courtesy naturals).','2026-06-08 02:02:37');
INSERT INTO "phase" VALUES('phase-11g','work/phase-11g-grace-note-length','merged',42,NULL,'5f877ab','duration category: grace-note written length modifiers ignored (grace <type> from group count only)','Croma export bug fixed (spec-correct)','Grace note <type> was derived solely from the grace-group note count, discarding each grace note written length modifier (/,2). Now the grace length multiplier is threaded through grace_note_event_model and the display duration is base(count) x multiplier, matching abc2xml ({B}=eighth, {B/}=16th, {AG}=16th, {A/G/}=32nd); grace notes still emit <grace/> with no <duration>. Full 10k: matches 6,364 -> 6,410 (+46); mismatch rows 204,096 -> 203,761 (-335); duration -335, zero changes in every other category (no regressions). Remaining duration is largely abc2xml hardcoded L:1/8 default (reference artifact, Croma spec-correct per ABC 2.1 4.6).','Harmony chord-symbol diffs (6,270) next; or %%MIDI directives over-rendered as words. Remaining missing/extra, pitch, octave, measure_alignment, accidental are mostly abc2xml reference artifacts (phantom measures, hardcoded L:1/8, courtesy naturals) per the phase-11 research.','2026-06-08 02:13:28');
INSERT INTO "phase" VALUES('phase-11h','work/phase-11h-harmony-chord-quality','merged',43,NULL,'c786c5b','harmony category: chord-quality misclassified by substring heuristic (dim swallowed by minor branch; aug/sus/6/dim7 unhandled)','Croma export bug fixed (spec-correct)','parse_chord_symbol mapped chord text to MusicXML <kind> with a naive substring chain so Xdim became minor and Xdim7/X7dim became dominant. Reordered/extended to classify diminished, diminished-seventh, augmented, suspended (2/4), major/minor sixth, and changed the fallback from other to major to match abc2xml. Full 10k: matches 6,410 -> 6,443 (+33); mismatch rows 203,761 -> 203,622 (-139); harmony -139, all other categories unchanged, 0 regressions. Still heuristic; next phase replaces it with a complete enumerated chord/decoration base.','Build a comprehensive table-driven base of ALL ABC decorations and ALL chord qualities -> exact MusicXML notations/kind, replacing the substring heuristics in parse_chord_symbol and decoration mapping for precision (per maintainer guidance).','2026-06-08 02:27:25');
INSERT INTO "phase" VALUES('phase-11i','work/phase-11i-chord-symbol-base','merged',44,NULL,'3de598f','harmony category: replace substring chord-quality heuristic with a structural, table-driven parser matching abc2xml grammar (root/accidental, kind table, trailing add-degrees, bass)','Croma export bug fixed (spec-correct)','Rewrote parse_chord_symbol as a structural parser following the ABC 2.1 4.18 grammar as implemented by abc2xml: root [A-G][#b=]?, greedy longest-match quality from a closed kind table (incl half-diminished, 9th/11th/13th, augmented-seventh), optional suspended token (kept only as kind when standalone), zero-or-more trailing chord degrees [#b=]?(2|4|5|6|7|9|11|13) emitted as degree-type=add (mirrors abc2xml which never emits subtract/alter), optional /bass, trailing (...) suppressed; leftover text => not harmony (=> words). Fixed dash being mis-read as a root flat (it is the minor quality). harmony 6131->5496 (-635), structural_matches 6443->6581 (+138), mismatch_rows 203622->202005 (-1617), export_failures 65 unchanged, 0 files regressed match->mismatch, all other categories flat or improved.','Remaining harmony residual is largely abc2xml reference artifacts; triage duration (21,358 / single-category files), measure_alignment (15,044), pitch (13,921) next.','2026-06-08 02:43:15');
INSERT INTO "phase" VALUES('phase-12','work/phase-12-core-module-breakdown','merged',46,NULL,'c04917e','Break oversized croma-core files into a stage/feature module tree (every impl file <=1000 lines, tests in sibling files)','Refactor (no behavior change)','Pure code-movement: music.rs (7906) split into syntax/, parse/, lower/; musicxml.rs (4241) into musicxml/*; fields.rs into parse/field/*; surface.rs into syntax/tune*. Tests moved to sibling *_tests.rs. Public API frozen (crate-root pub use names preserved; cli/fmt/lsp compile unchanged). Largest impl file now 972 lines (was 7906). Verified: cargo test/clippy/fmt + pytest green, and full 10k MusicXML output BYTE-IDENTICAL to pre-refactor (diff -r, 202005 rows unchanged). History preserved via git mv. Spec/plan under docs/superpowers/.','Resume parser/exporter quality work on the new module tree: %%MIDI directives over-rendered as words, remaining duration/pitch/measure residuals (mostly abc2xml reference artifacts).','2026-06-08 07:35:11');
INSERT INTO "phase" VALUES('phase-13','work/phase-13-midi-directive-words','merged',47,NULL,'843d10f','direction/extra_in_croma: preserved %% stylesheet directives (overwhelmingly %%MIDI) rendered as visible <words> directions','Croma export bug fixed (spec-correct)','Croma rendered preserved %% stylesheet directives (1138 %%MIDI occurrences across 551 files, plus a few junk/formatting ones) as visible <words> directions. abc2xml emits nothing for them: ABC 2.1 stylesheet/MIDI directives control playback/formatting, not printed text. Removed the preserved-directive words emission from the MusicXML writer (write_initial_directions; deleted write_preserved_directive in musicxml/direction.rs); model preserved_directives kept for round-trip/formatter use. TDD regression test added (midi_directives_are_not_emitted_as_words); 2 existing tests that pinned the old words behavior updated. Full 10k: structural matches 6581->6904 (+323), mismatch rows 202005->200345 (-1660), direction 1470->784 (-686), extra_in_croma 52027->50993 (-1034). Per-file: 0 match->mismatch regressions, 323 mismatch->match, 535 files fewer rows, only 2 already-mismatched files +6 rows total (positional alignment cascade; measure_alignment root unchanged). Export failures 65 unchanged.','Accidental category (6,249 rows / 532 single-cat files) was confirmed this session to be an abc2xml reference artifact: abc2xml re-prints accidentals that carry through the measure (ABC 2.1 sec 6) while Croma correctly prints them once - justify, do not fix. Next genuine Croma item: unclosed [ chord swallowing past a barline in parse_chord (~29 rows). Remaining duration (21,358), pitch (13,921), measure_alignment (15,044) residuals are largely reference artifacts (phantom measures, hardcoded L:1/8); re-derive targets from a fresh comparison.','2026-06-08 08:04:27');
INSERT INTO "phase" VALUES('phase-14','work/phase-14-voice-middle-octave','merged',48,NULL,'5e6657c','octave category: ABC voice/clef modifier middle=<pitch> ignored, so voices (esp. clef=bass middle=d) emitted two octaves too high','Croma export bug fixed (spec-correct)','Croma dropped the ABC middle=<pitch> clef/voice modifier entirely (token fell through to VoiceProperties.other), so a clef=bass middle=d voice emitted notes two octaves too high (bass e -> E5 instead of E3). Implemented middle= per abc2xml gtrans formula: octnum=(4 if uppercase else 5)+(apostrophes or -commas), gtrans=(3 if note in {A,F,D} else 4)-octnum; added to voice_octave_shift alongside existing clef +-8/+-15 and octave= handling. Plumbed middle through parse/field/voice.rs, surface VoiceProperties, VoicePropertiesModel, lower voice_properties_model AND merge_voice_properties (body V: switch). TDD: unit tests (d=-2,D=-1,B=0,c=-1,malformed=0) plus e2e (clef=bass middle=d emits octave 3). Full 10k: structural matches 6904->6936 (+32), mismatch rows 200345->196757 (-3588), octave 9972->6397 (-3575), slur 307 (-13), every other category unchanged. Per-file: 0 match->mismatch regressions, 32 mismatch->match, 0 files worse by any row, 57 files fewer rows. Export failures 65 unchanged.','K-line clef-octave propagation (octave residual ~298 rows / 4 files incl tune_002746 185 rows): clef/octave=/treble+-8 on a K: line not extracted into voice properties (lower/voice.rs set_key only updates accidental policy), so voice_octave_shift never sees them. Same machinery just built; plumb clef/octave from the K: KeySignature into VoicePropertiesModel. Then barline genuine bugs: volta number-list split (|1,3 -> two <ending> instead of one number 1,3; 44 rows/14 files; writer fix musicxml/score.rs unique_endings + barline.rs) and double-bar dropped (spaced/line-split | | coalesced to Double; 81 rows/38 files; lower/timeline.rs). Accidental (6249) confirmed reference artifact.','2026-06-08 08:20:40');
INSERT INTO "phase" VALUES('phase-15','work/phase-15-kline-clef-octave','merged',49,NULL,'6710b86','octave category: clef/octave directives on a K: line dropped (parser captured only tonic/mode/accidentals), so per-voice octave shift never applied','Croma export bug fixed (spec-correct)','ABC 2.1 sec 4.6 allows clef/octave modifiers on K: lines, not only V:. Croma key parser dropped clef=/octave=/treble+-8/bass/middle= tokens on K: lines. Now parse_key feeds the post-tonic remainder through parse_voice_properties and the lowering merges the clef/octave/middle/transpose into the CURRENT voice only (abc2xml per-voice scoping): header K: seeded in MultiVoiceLowering::new, body K: in apply_key_change, inline [K:] in apply_inline_key_clef_properties. Also extended parse_voice_properties to recognize BARE clef shorthands (treble+8, bass, alto...) since the corpus uses K:C treble+8 (not clef=); this fixes the same latent drop on V: lines too. voice_octave_shift (built in phase-14) then applies the shift unchanged. TDD: parse tests (Dm octave=1, bare treble+8) + e2e (single-voice K: octave=1 shifts +1; multi-voice V:1 treble+8 / V:2 treble-8 scoped, no leak). Full 10k: structural matches 6936->6939 (+3), mismatch rows 196757->196215 (-542), octave 6397->5855 (-542), every other category unchanged. Per-file: 0 match->mismatch regressions, 3 improved, 0 files worse, 6 files fewer rows. Export failures 65.','Barline genuine bugs (next): (1) volta number-list split - ABC |1,3 / :|2,4 emitted as two separate <ending> elements instead of one <ending number="1,3"> (MusicXML ending-number is a comma list); 44 rows/14 files; writer fix in musicxml/score.rs unique_endings + musicxml/barline.rs write_ending_barline. (2) double-bar dropped - two | separated only by whitespace/line-break (| | or line-split) should coalesce to a Double light-light bar; 81 rows/38 files; lower/timeline.rs. Then re-derive from a fresh comparison. Accidental (6249) and the missing/extra/duration bulk remain abc2xml reference artifacts.','2026-06-08 08:28:42');
INSERT INTO "phase" VALUES('phase-16','work/phase-16-volta-number-list','merged',50,NULL,'56828ea','barline category: multi-pass volta |1,3 / :|2,4 emitted as two separate <ending> elements instead of one <ending number=1,3>','Croma export bug fixed (spec-correct)','MusicXML <ending> number attribute is type ending-number (a comma-separated list of passes), so an ABC multi-pass volta like |1,3 must be ONE element <ending number="1,3">. unique_endings in musicxml/score.rs did a double flat_map that flattened each RepeatEndingModel bracket parts [Single(1),Single(3)] into separate strings, so write_ending_barline emitted two <ending> elements. Added ending_number_string helper that comma-joins a bracket parts (no space, matching abc2xml) and dropped the inner flat_map. TDD e2e: |: GABc |1,3 GA :|2,4 Bc :| now emits one number=1,3 and one number=2,4. Full 10k: structural matches 6939->6953 (+14), mismatch rows 196215->196161 (-54), barline 3341->3287 (-54), every other category unchanged. Per-file: 0 match->mismatch regressions, 14 improved, 0 files worse, 18 files fewer rows. Export failures 65.','Barline double-bar dropped (next, 81 rows/38 files): two | separated only by whitespace or a line break (| | spaced, or line-split | ... |) should coalesce to a single Double (light-light) barline per ABC 2.1 sec 4.8/6 liberal bar recognition, but Croma keeps them as two Regular barlines which emit nothing. Fix in lower/timeline.rs (coalesce two adjacent zero-duration Regular barline events across whitespace/line-break into Double; see VoiceTimelineBuilder push Barline arm). Then re-derive from a fresh comparison; accidental/missing/extra/duration bulk remain abc2xml reference artifacts.','2026-06-08 09:00:41');
INSERT INTO "phase" VALUES('phase-17','work/phase-17-chord-ties','merged',51,NULL,'9729b4c','tie category: ABC chord ties dropped - chord-internal [DA-] discarded by parser, whole-chord [A,E]- tied only one member','Croma export bug fixed (spec-correct)','ABC 2.1 sec 4.11: ties may be used into, out of and between chords (each matching member ties independently). Croma dropped ALL chord ties: (A) parse_chord had no - arm so [DA-] became unknown_chord_token and was discarded (46 rows/10 files); (B) whole-chord [A,E]- tied a single event_index (last member) by one (step,octave) signature, dropping when unmatched and never tying multiple members (11 rows/4 files). Fix: parse a trailing - on a chord member into a tie marker on that member; generalize the tie model from Option<PendingTie> to Vec<PendingTie> with a captured (step,octave) signature, resolving each pending tie per-member against the next group, consuming each next note at most once, dropping only unmatched members. apply_tie now registers every member of the last group (whole-chord tie). phase-11d accidental preservation generalized to all pending ties. Single-note tie path unchanged (1-element case). Writers unchanged (already per-note). Cross-checked dev/abc (which itself ties only the last member - imperfect; ABC 2.1 is the oracle). TDD: parser [DA-], whole-chord [CE]-[CE] (4 tied), internal [DA-]2[FA] (A only), standalone C2-C2 guard. Full 10k: structural matches 6953->6967 (+14), mismatch rows 196161->195951 (-210), tie 610->399 (-211), accidental +1 (single-row cascade). Per-file: 0 match->mismatch regressions, 14 improved, 38 fewer rows; 2 heavily-broken files (+11/+4 tie) now emit the reference tie COUNT exactly (14=14) - positional cascade, not wrong ties. tune_013006 8=8, tune_000334 18=18. Export failures 65.','Slur grace-in-slur (next, genuine bug, 42 rows/20 files): ABC ({grace}note) opens a slur before a grace group; per ABC 2.1 sec 4.11/4.20 the slur must start on the FIRST grace note, but Croma puts start+stop on the main note (degenerate count=1) because grace notes are folded into a GraceGroupAttachment (not timed events) so attach_pending_slur_starts cannot target them. Fix: give grace notes a slur-attachment slot (model + lower/voice.rs attach_pending_slur_starts) and emit <notations><slur> on grace <note> in musicxml; mirror dev/abc parser.rs consume_grace lines 700-733. CONFIRMED ARTIFACTS (do not fix): double-bar | | spaced/line-split rendered light-light by abc2xml is NOT spec-mandated (ABC 2.1 sec 4.8 liberal recognition is for CONTIGUOUS sequences; sec 4.9 shows spaces are significant) - abandoned a coalescing attempt that regressed barline +555/-112 matches; accidental carried-through re-emission (6249); missing/extra/duration bulk.','2026-06-08 09:16:24');
INSERT INTO "phase" VALUES('phase-18','work/phase-18-grace-slur','merged',52,NULL,'fd54652','slur category: a slur opening before a grace group ({grace}note) dropped the slur from the grace, landing a degenerate start+stop on the main note','Croma export bug fixed (spec-correct)','ABC 2.1 sec 4.11 (slurs connect the first and last note of a series) + sec 4.20 (construct order: grace notes precede the main note): in ({d2}c4) the slur must START on the first grace note. Croma folds grace notes into a GraceGroupAttachment (not timed events), so attach_pending_slur_starts skipped them and put both start and stop on the main note (degenerate one-note slur). Fix: added slurs: Vec<SlurAttachment> to the lowered GraceGroupAttachment; attach_pending_slur_starts now compares the slur-open span to the note leading grace groups and, when the slur ( precedes the grace { (earliest such group), attaches the slur START to that grace group (leading_grace_group_after/attach_slur_to_grace) instead of the timed note; slur STOP unchanged. Writer write_grace_group emits <notations><slur> on the FIRST grace note via the normal write_notations path. Cross-checked dev/abc consume_grace. TDD: ({g}c4) slur on grace; guard {g}c(de) slur on main; guard (DEF) plain slur. Full 10k: structural matches 6967->6991 (+24), mismatch rows 195951->195798 (-153), slur 307->154 (-153), every other category unchanged. Per-file: 0 match->mismatch regressions, 24 improved, 0 files worse, 59 fewer rows. Export failures 65.','Tangential bug found this phase (genuine, not yet fixed): the {grace}(note) form (grace group immediately FOLLOWED by a slur-open, e.g. {g}(c4) or {d2}(c4)) drops the grace note entirely before lowering - a parser/attachment issue distinct from the slur-on-grace case just fixed; worth a focused phase. Then slur bucket B (slur spanning barline/spacer, stop lands one note early, ~15 rows/10 files). Re-derive remaining targets from a fresh comparison; accidental(6250)/missing/extra/duration/measure_alignment bulk and double-bar | | remain abc2xml reference artifacts.','2026-06-08 09:35:43');
INSERT INTO "phase" VALUES('phase-19','work/phase-19-broken-rhythm-barline','merged',53,NULL,'794815e','duration: broken-rhythm sign after a barline bound backward across the bar to the previous measure note','Croma export bug fixed (spec-correct)','ABC 2.1 sec 4.4: > dots the previous note and halves the next; after a barline a leading >/< has no previous note so it is void. Croma already voided the mirror cases (dangling-right A>| and very-first-token), but a >/< after a bar still bound to time_groups.last() from the previous measure (c2|>d dotted c2 across the bar). Added broken_left_available flag on LoweringState: true when a timed note group is pushed in the current measure, reset false at each barline (in finish_pending_broken_at_boundary); apply_broken_rhythm voids (missing_left diagnostic) when not available. Found by mining ro-ag/ABC solved-problems list (its bug 9), then independently verified against the ABC 2.1 spec and corpus (NOT taken on faith). Of ro-ag/ABC 14 documented bugs, current croma already handled 12; only this one and a spec-AMBIGUOUS grace-accidental-propagation (bug 4, deliberately NOT fixed - no clear spec mandate) reproduced. TDD: c2|>d e -> 8,4,4; B|>d -> 4,4,4; guards a>b, A>|B, c2>d (no bar), c>{g}d grace-transparency. Full 10k: structural matches 6991->6991 (+0), mismatch rows 195798->195779 (-19), duration -4, measure_alignment -15; 0 match->mismatch regressions, 0 files worse, 1 file fewer rows. Low corpus prevalence (5 files) but a clean spec-correctness fix. Export failures 65.','croma is at a high spec-compliance plateau: ro-ag/ABC full-corpus audit reports 99.62% pitch+duration exact and current croma handles 12/14 of its documented bugs plus this one. Remaining 195,779 mismatch rows are dominated by abc2xml REFERENCE ARTIFACTS already classified (accidental carried-through re-emission 6250; missing/extra/measure_alignment positional cascades from abc2xml representation choices incl multi-measure-rest Z/X expansion, duration ROUNDING to its divisions grid, BROKEN_UNDEFINED sec 4.4, MALFORMED input). Next: re-derive any remaining genuine single-category signals from a fresh phase-19 comparison (slur bucket B - slur spanning barline stop one note early ~15 rows; the {grace}(note) drops-grace bug flagged in phase-18); otherwise the residual is justify-not-fix. Treat abc2xml AND ro-ag/ABC as orientation; ABC 2.1 spec is the oracle.','2026-06-08 09:48:33');
INSERT INTO "phase" VALUES('phase-20','work/phase-20-grace-before-slur','merged',54,NULL,'cccd79a','missing_in_croma + cascades: a grace group followed by a slur-open (or any flush trigger) before its note was silently dropped','Croma export bug fixed (spec-correct)','ABC 2.1 sec 4.20: a grace group attaches to the note it precedes; an intervening slur-open/decoration does not detach it. parse_slur (and other constructs) call flush_pending_attachments which drains buffered grace groups into standalone MusicItem::GraceGroup items, and the lowering match arm for standalone GraceGroup was a NO-OP => {} so {g}(c4), {g}!fermata!c, etc. dropped the grace entirely. Fix (lowering buffer, approach 1 - covers ALL flush triggers uniformly): added pending_grace_groups: Vec on LoweringState; the standalone GraceGroup arm now buffers instead of dropping; take_timed_attachments prepends the buffer onto the next note/rest/chord, cleared at a barline (orphaned grace voided per spec) and per-voice (isolation). phase-18 slur-before-grace (({g}c4)) intact: slur-after-grace ({g}(c4)) starts on the MAIN note. Found via phase-18 tangential note then verified against spec + corpus (62 files have }( ). TDD: {g}(c4) grace+slur-on-main; guards ({g}c4), {g}c4, orphaned {g}|. Full 10k: structural matches 6991->7028 (+37), mismatch rows 195779->191534 (-4245); EVERY category improved (missing_in_croma -1973, duration -640, pitch -609, accidental -324, tuplet -235, measure_alignment -150, voice -150, octave -147) because each dropped grace caused positional cascades across all downstream notes. 0 match->mismatch regressions, 0 files worse, 65 fewer rows. Export failures 65.','croma at a very high spec plateau (191,534 rows, structural matches 7028). Remaining residual dominated by abc2xml reference artifacts (accidental carried-through 5926; missing/extra/duration/measure_alignment positional cascades from abc2xml representation choices: multi-measure-rest Z/X expansion, duration ROUNDING to its divisions grid, phantom empty measures, BROKEN_UNDEFINED sec 4.4, MALFORMED). Re-derive any final single-category signals from fresh phase-20 comparison (slur bucket B slur-spanning-barline stop one note early ~15 rows is the last small known genuine lead). ABC 2.1 spec is the oracle; abc2xml AND ro-ag/ABC are orientation only.','2026-06-08 15:16:48');
INSERT INTO "phase" VALUES('phase-21','work/phase-21-unclosed-chord-barline','merged',55,NULL,'c406cb7','missing/extra cascades: an unclosed [ chord scanned past bar lines, swallowing and deleting whole measures','Croma export bug fixed (spec-correct)','A chord cannot span a bar line (ABC 2.1 sec 4.18: chords are note groups within a measure). parse_chord member loop had no | case, so an unclosed [ (no ] before the bar) consumed following | barlines as malformed tokens and discarded the multi-measure run as one unclosed_chord, deleting real music. E.g. [ |: ... (space after [ routes to parse_chord) swallowed a 4-measure line; ["bis" ... swallowed bars. Fix: added a | => break arm in the parse_chord member scan that stops at a bar line WITHOUT consuming it (self.index left at the |, caller re-reads it as a barline); the unclosed-chord recovery then covers only the partial [... run. Valid chords always close with ] before any | so zero risk to them (guards: [CEG], [!f!E2A2], .[CE]2, [CEG]|D unchanged). Found via the croma-fewer-measures research (separated from the abc2xml phantom-empty-measure-per-annotation-line artifact, which is justify-not-fix). TDD: [ |: CDEF | GABc | and ["x" CDEF | GABc | preserve following measures; chord guards. tune_009252 12->16 measures (ref 17), tune_002703 7->11 (exact). Full 10k: structural matches 7028->7029 (+1), mismatch rows 191534->187908 (-3626); missing_in_croma -2007, extra_in_croma -865, duration -404, pitch -195, slur -24, plus small internal reshuffles (accidental +40, harmony +8, lyric +3) within net-improved files. Per-file: 0 match->mismatch regressions, 0 files worse overall, 13 files fewer rows. Export failures 65.','croma at a high spec plateau (187,908 rows, matches 7029). The croma-fewer-measures research classified the dominant remaining missing/extra driver as the abc2xml phantom-empty-measure-per-standalone-annotation-line artifact (e.g. tune_003837 8 empty measures for 8 part-label lines "A"\ etc.) - JUSTIFY, DO NOT FIX (croma folded output is more correct MusicXML). Remaining residual: accidental carried-through (5966), abc2xml duration ROUNDING, multi-measure-rest Z/X expansion, multipart layout, MALFORMED input - all abc2xml reference artifacts. Last small known genuine lead: slur bucket B (slur spanning barline, stop one note early ~15 rows). Otherwise croma has reached the spec-compliance plateau. ABC 2.1 is the oracle; abc2xml and ro-ag/ABC are orientation only.','2026-06-08 15:41:21');
INSERT INTO "phase" VALUES('phase-22','work/phase-22-phantom-empty-measure','in_progress',NULL,NULL,NULL,'missing/extra/measure cascades: croma emitted a phantom empty <measure> for a measure holding only barline tokens (trailing/adjacent/split | | , |]| , ]| , leading | | | |)','Croma export bug fixed (spec-correct)','Found via a per-file divergence prover (tools/prove_divergences.py): of 2906 differing files, 72 were REVIEW (unexplained); a subagent classified them and found 29 single-voice files with ONE genuine croma bug - a measure containing only barline tokens (no note/rest) was kept as a phantom empty <measure>, because is_empty_measure_start() and finish() trailing-pop in lower/timeline.rs gated on events.is_empty() and a barline-only measure is not events-empty. Per ABC 2.1 sec 4.8 a run of adjacent/split bar lines (| |, |]|, ]|) is a single boundary, not a measure of music. Fix: added is_barline_only_measure(); finish() pops a trailing barline-only measure and is_empty_measure_start() coalesces interior barline-only measures (measure_index>0), BUT gated to SINGLE-VOICE tunes (may_coalesce_barline_only = single_voice && no overlays) because in multi-voice a barline-only voice line is a legitimate TACET bar that must be kept for alignment (regression caught in 10k: tune_006766 159->157 +861 rows; fixed by the guard). single_voice flag threaded from lower/mod.rs. TDD: trailing | | / |]| ->1 measure, mid-tune |]+|: , guards (||, separate lines, leading rest, leading pickup), plus a multi-voice tacet-bar-kept test. Full 10k: structural matches 7029->7031 (+2), mismatch rows 187908->185089 (-2819); EVERY category down (extra -1215, missing -645, pitch -262, duration -265, measure_alignment -110, tuplet -65, accidental -79, octave -92, voice -58). Per-file: 0 multi-voice regressions; 4 single-voice files (008158/008268/008270/015731, all |>| void-broken-rhythm trailing) go match->mismatch by 16 rows each because croma is now MORE spec-correct (notes identical, the void > makes |>| == | |, no trailing measure) while abc2xml inconsistently keeps the empty measure - a justified spec-first divergence, not a defect. 6 files improved to match, 27 fewer rows. Export failures 65.','Per-file prover (tools/prove_divergences.py) now leaves only artifact-class verdicts + a handful of single-voice |>|/bracket files where croma is more correct than abc2xml. Remaining known minor items: the [-after-barline swallow (||[, :|[ -> parse/barline.rs stops scan at [, mis-reads [text as unclosed chord; tune_004361/005568, small) and abc2xml |>| empty-measure inconsistency (croma correct). Re-run the prover after this merge and regenerate docs/comparison per-file-manifest. Otherwise croma is at the spec-compliance plateau; ABC 2.1 is the oracle, abc2xml and ro-ag/ABC are orientation only.','2026-06-08 16:54:12');
INSERT INTO "phase" VALUES('phase-23','work/phase-23-barline-run-phantom','complete',NULL,NULL,NULL,'RESIDUAL_PHANTOM_CROMA: thick ] followed by an adjacent or backslash-continued barline run such as ]||: opened an interior phantom empty measure','Croma parser/export bug fixed (spec-correct)','Fixed the remaining known Croma phantom-measure residual. ABC 2.1 sec 4.8 treats adjacent bar-line tokens as one boundary. parse_barline now scans through ] only for the narrow ]|| run shape, preserving final spellings such as |]| and :|]. parse_music_document also merges only backslash-continued barline runs where the previous raw barline contains ], covering tune_014316 without broad interior barline-only folding. TDD added for CDEF]||: GA |, second-ending [2 C3]||:, continued [2 C3]\ then ||:, ||: guard, |]| final spelling, and existing multi-voice tacet alignment guard. tune_014316 and tune_014317 now export 22 measures and 53 notes each. Exact origin/main baseline was 7031 structural matches and 185089 mismatch rows. Phase-23 full 10k is 7031 structural matches and 184806 mismatch rows, with zero match-to-mismatch regressions, zero worse files, and no mismatch category increases. The divergence prover reports RESIDUAL_PHANTOM_CROMA=0 and REVIEW=0.','No known genuine Croma issues remain in the abc2xml divergence manifest. Continue with spec-first parser work only from fresh evidence; abc2xml remains a comparison baseline, not the correctness oracle.','2026-06-08 18:40:59');
INSERT INTO "phase" VALUES('phase-24-fmt','work/fmt-subcommand','merged',62,'https://github.com/ro-ag/croma/pull/62',NULL,'Build the croma fmt subcommand: canonical idempotent+lossless ABC formatter (croma-fmt rebuilt from stub) plus pitch-preserving --auto-fix curations, gated by runtime pitch-sequence verification','New feature (formatter gate lifted by abc2xml-divergence proof)','croma-fmt: span-anchored token-preserving engine; format/is_formatted/auto_fix with FixResult. Curations: detached length, chord-symbol-in-brackets unwrap, doubled tempo (each runtime-verified pitch-preserving). CLI migrated to clap (derive) + colored output; fmt has stdout/--check/-w/--auto-fix. 10k corpus round-trip: 0 notes changed, 0 idempotency failures, 2682 reformatted.','Iterate the --auto-fix catalogue: redundant bar-line collapse (phase 22/23 work) and %%MIDI/stylesheet directive placement; then per-field re-spacing/order with individual safety proofs','2026-06-08 21:21:17');
INSERT INTO "phase" VALUES('phase-25-fmt-barline','work/fmt-barline-collapse','merged',63,'https://github.com/ro-ag/croma/pull/63',NULL,'auto-fix catalogue class 2: redundant bar-line collapse (spaced | | and ]||: runs) to canonical single boundary, preserving repeat/volta/final semantics','New auto-fix curation (formatter increment)','Added FixKind::RedundantBarline gated by a NEW structure-preserving gate (full MusicXML equality) distinct from the pitch-sequence gate used by rhythm/tempo repairs. Canonical-collapse heuristic proposes |, |:, :|, :|: and the gate proves each rendering-neutral (real || / |] left untouched). Corpus harness now also asserts canonical fmt yields byte-identical MusicXML. 10k: notes_changed 0, not_idempotent 0, canonical_xml_changed 0, auto_fixed 3290.','Auto-fix class 4: normalise %%MIDI/stylesheet directive placement (structure-gated); then per-field re-spacing/order with individual proofs','2026-06-09 00:20:15');
INSERT INTO "phase" VALUES('phase-26-fmt-field-spacing','work/fmt-field-spacing','merged',64,'https://github.com/ro-ag/croma/pull/64',NULL,'auto-fix: field-value re-spacing — trim whitespace after a field colon (K: C -> K:C), spec-grounded no-space convention','New auto-fix curation (formatter increment)','Added FixKind::FieldSpacing, structure-gated (MusicXML equality) so alignment-sensitive w:/s: values are reverted; overlap resolution prevents Q: field-spacing colliding with doubled-tempo. 10k: notes_changed 0, not_idempotent 0, canonical_xml_changed 0, auto_fixed 7001.','Catalogue items exhausted except %%MIDI/stylesheet directive placement (deferred: croma does not render %%MIDI to MusicXML so the structure gate cannot protect it)','2026-06-09 01:19:04');
INSERT INTO "phase" VALUES('phase-27-abc-writer','work/abc-writer','merged',65,'https://github.com/ro-ag/croma/pull/65','44cf113e682eca5629eb481b1d375de1984c71a5','docs/superpowers/plans/2026-06-09-abc-writer.md (Score->ABC writer slice 1)','New feature (XML->ABC epic: Score->ABC canonical writer, slice 1)','Added croma_core::write_abc emitting canonical ABC (headers, single voice notes/rests/durations/accidentals/octaves, barlines+repeats+endings, ties); exposed via croma dump abc. Output is a croma fmt fixed point and round-trips with identical structural projection. Corpus: 3149/10000 in-scope (31.49%), 0 structural diffs.','Slice 2: grow in-scope coverage (chords -> tuplets -> voices -> lyrics ...) until full corpus round-trips; then MusicXML->Score reader (roxmltree, feature-gated).','2026-06-09 05:52:04');
INSERT INTO "phase" VALUES('phase-28-abc-writer-coverage','work/abc-writer-coverage','merged',66,'https://github.com/ro-ag/croma/pull/66','07451193a8bc52a2e2c2895a291447f4249bad98','Score->ABC writer coverage expansion','New feature (XML->ABC epic: writer construct coverage)','Added slurs, decorations, chord symbols, annotations, chords, tuplets, grace, and an accidental safety-net to write_abc; grew structural projection accordingly. Corpus in-scope coverage 31.5%->57.0%, 0 structural diffs.','Phase C lyrics (w: aligned line) then Phase D multi-voice (V:); then remainder (overlays, leading-barline, mid-tune key/meter need parser support).','2026-06-09 18:40:42');
INSERT INTO "phase" VALUES('phase-29-abc-writer-coverage-2','work/abc-writer-coverage-2','merged',67,'https://github.com/ro-ag/croma/pull/67','126bfaaf6c5cc77b9b7285853674486756f2ab1d','Score->ABC writer: lyrics, symbols, multi-voice, overlays, exotic barlines','New feature (XML->ABC epic: writer construct coverage to ceiling)','write_abc now covers w:/W: lyrics, s: aligned symbols, dotted/invisible/liberal barlines + split-token rejoin, spacers, multi-voice V: with properties and octave-shift compensation, overlays, %%score; harness regex anchoring + projection growth (lyrics, voice, backup, part ids). Corpus 57%->92.49%, 0 structural diffs. Parser-bug backlog catalogued in docs/parser-backlog.md.','Parser-fix phase per docs/parser-backlog.md: quoted-text-before-grace/slur drop, dropped-tie accidental carry (diverges from abc2xml), rest-led tuplet Start; THEN remove writer safety-net workarounds; then mid-tune K:/M: model events; then MusicXML->Score reader.','2026-06-09 22:50:01');
INSERT INTO "phase" VALUES('phase-30-parser-fixes','work/parser-bug-fixes','merged',68,'https://github.com/ro-ag/croma/pull/68','cc8afbd866265243d454c212f320b38fda26a3cb','Parser bugs from the write_abc round-trip proof (docs/parser-backlog.md): quoted-text drops, dropped-tie accidental leak, rest-led tuplets, octave-shift panics','Bug fix (parser/lowering correctness; writer workaround removal)','Pending quoted text/decorations now survive grace groups, slur-opens and tuplet markers; dropped ties undo their barline-preserved accidental carry (from_pending_tie provenance) and mid-tune M:/K: no longer clear carries (spec 11.3, abc2xml parity); tuplet roles land on rests (Start/Continue/Stop); octave shifts clamp instead of panicking; inline [I:] warns instead of silent drop. Writer accidental safety-net and tuplet has_start skip removed; harness rest-led-tuplet and [I:tuplets gates removed, lower_fail labeled+bucketed (65 = header-only corpus fragments). Round-trip 92.49->92.63 pct, 0 diffs; reference comparison matches 7031->7274, mismatch rows 184806->179562, no category increases.','Mid-tune K:/M: change events in the Score model (~5.5 pct unlock; own brainstorm+spec phase), then the MusicXML->Score reader epic. Smaller: quoted text before barline (abc2xml keeps it - verdict 2026-06-09), nested tuplets in the writer, overlay voice-number collision, syllabic always single.','2026-06-10 16:31:27');
INSERT INTO "phase" VALUES('phase-31-compare-cache','codex/phase-31-compare-perf','merged',69,'https://github.com/ro-ag/croma/pull/69','dfd2682366dba5da6af5646e1b549810d4cece1c','Corpus comparison runtime (user-directed): every 10k music21/polars compare re-parsed all ~20k MusicXML files with music21 (~53 pct of ~30-40 s/run) and re-joined every pair, even though the reference side never changes and most croma exports are unchanged between runs.','Tooling performance (comparison cache; no parser/writer behavior change)','Added tools/compare_cache.py: content-addressed SQLite cache (WAL) with two layers - facts (per MusicXML file, key = sha256(bytes) + extractor version) and results (per croma/reference pair, key = both hashes + tool version + relative path + options). Wired into music21_polars_corpus_compare.py with --cache-db/--no-cache/$CROMA_COMPARE_CACHE_DB (default docs/untracked/cache/compare-cache.sqlite), relative_path indexes for by-name lookup/invalidation, 14-day stale prune, cache stats in the report. Cached and uncached outputs verified byte-identical on the full 10k corpus. Report-only rerun 29.0 s -> 0.63 s; rerun after a 448-file parser change 29.0 s -> 2.5 s; component selector with mismatch tables ~30 s -> 3.1 s; cold run unchanged (~30 s, 42 MB cache). --jobs default changed 1 -> 0 (auto). Follow-up (same branch): comparison made columnar - comparison_key now vectorized via struct.json_encode (byte-identical to per-row json.dumps, ~10x faster single-threaded), fact values encoded once per row with a fast scalar path, full join keyed on comparison_key alone with per-file constants as literals; POLARS_MAX_THREADS=1 per worker kept deliberately (process-level parallelism beats polars threads for thousands of small frames). Per-task cost 37.9 -> 29.8 ms/file (-21 pct); uncached 10k A/B on the same contended machine 74.0 -> 61.0 s. Structured JSONL logging is now the default (--log-format text for legacy): start/progress events on stderr, one summary event on stdout mirroring report keys, for agent consumption. Encoder follow-up: fact-value and cache-payload encoding moved to orjson (new python tooling dep). Scalars byte-identical to stdlib; containers compact - both sides share the encoder so verdicts unchanged (full 10k counts identical: 7274/2661/179562). Value encode 1.85 -> 0.30 ms/file-pair (vs 1.20 with the hand-rolled fast path, now deleted); row building 8.6 -> 2.7 ms; facts-cache blobs interoperate across codecs (plain JSON both ways). Re-warm after version rotation 8.0 s, fully warm 0.65 s. Schema v3 (typed values): fact/comparison tables store values in native typed columns (value_kind + value_str/value_int/value_float/value_json; bool in value_int) instead of one JSON-encoded string; raw_value now explicit-only; rows built as positional tuples (orient=row). Match semantics proven equivalent to v2: full 10k counts and all 15 category totals identical (7274/2661/179562), per-file summaries byte-identical, report identical except schema/column metadata. Row building 2.7 -> 1.8 ms/file-pair, offset by wider-frame serialization (net wall-clock neutral: no-cache 23.1 s, rewarm 7.5 s, warm 0.68 s, selector 3.1 s); the win is queryability - typed parquet columns filter natively without JSON-quoted strings. REPORT_SCHEMA bumped to croma-music21-polars-corpus-compare-v3; v2 baseline mismatch files still aggregate for deltas (filename-based).','Mid-tune K:/M: change events in the Score model (~5.5 pct unlock; own brainstorm+spec phase), then the MusicXML->Score reader epic. Smaller: quoted text before barline (abc2xml keeps it - verdict 2026-06-09), nested tuplets in the writer, overlay voice-number collision, syllabic always single.','2026-06-10 20:15:30');
INSERT INTO "phase" VALUES('phase-32-midtune-key-meter','work/midtune-key-meter','merged',70,'https://github.com/ro-ag/croma/pull/70','0d1bebbd8a71f08fa0709307ec21264372363023','Mid-tune K:/M: change events end-to-end','New feature (Score model + lowering + MusicXML export + ABC writer)','TimedEventKind::KeyChange/MeterChange recorded by lowering (per-voice [M:] scoping matching abc2xml, clef-only K: guard, header-aware value dedupe, late-voice seeds, tie-pitch carry across mid-measure key changes); <attributes><key>/<time> exported at the event cursor incl. mid-measure; writer emits inline [K:]/[M:]; no synthetic M:4/4 header; change-event-only measures stay coalescible. Round-trip 92.63->99.25 pct 0 diffs (projection now asserts KEY/TIME); reference comparison +262 fully-matching files, -4861 mismatch rows, no category increases.','Writer-side: position-aware octave compensation for mid-tune clef +-8 changes (1 tune); nested tuplets; remaining items in docs/parser-backlog.md (quoted text before barline, overlay voice collision, syllabic). Then the MusicXML->Score reader epic (roxmltree, feature-gated).','2026-06-11 06:52:31');
INSERT INTO "phase" VALUES('voice-field-same-line-music','work/voice-field-same-line-music','complete',NULL,NULL,NULL,'Body V: same-line music swallowed when first token contains = (user-reported; corpus hit tune_014784 dropped 4 of voice 2''s 12 measures)','Bug fix (parser correctness; no silent V: text discard)','looks_like_same_line_music treated any first token containing = as a key=value voice parameter, so music starting with a natural accidental (=C2D2) or carrying one mid-token (E2=F2) was silently parsed as voice properties, yielding an empty measure with no diagnostic. Parameter detection now requires a non-empty alphabetic key before the =; a keyless = token left on a body V: line without recovered music emits warning abc.field.voice_property_ignored instead of vanishing. 3 regression tests added. Full 10k before/after compare: structural matches unchanged at 8118; only tune_014784 moved (+218 extra_in_croma rows because the abc2xml reference is degenerate there: 1 empty measure, 0 notes per part), croma now exports its full 12 measures per voice.','Writer residuals per phase-32 backlog; MusicXML->Score reader epic.','2026-06-11 15:15:51');
INSERT INTO "phase" VALUES('phase-33-compare-triage','codex/phase-33-compare-triage','merged',NULL,NULL,'8c76fc824463fda8ee6ddab74e07cc064728d873','Comparison-residue forensic triage + confirmed-bug fixes (per-cause adversarially verified ledger: docs/comparison/abc2xml-divergences/12-phase33-triage-ledger.md)',NULL,'Comparator now compares sounding alteration (+582 matches). Fix batches: boundary-attachment data loss (text/dynamics/graces survive barlines/EOL), multi-measure volta ending stops (905-file bug), ending-before-repeat XSD order, wedge + stopped decorations, liberal barline runs keep strongest meaning, lone-colon boundary, |]: merge, body L: voice scoping, mid-tune Q: tempo events (model+XML+writer), chord-root case sensitivity. Matches 7536->8825, rows 174701->168183, 0 per-file regressions at every batch; round-trip 99.25%/0 diffs unchanged.','Ledger OPEN bugs: multirest XML encoding (6 files), chord-member slur drops (~25), tuplet written-type, accidental trio, octave pair, lyric trio, nospace-key, complex-meter time, [-quoted volta. Then Mission B on codex/phase-34-midi: translate %%MIDI program/channel/transpose/drummap + control CC7/CC10 per oracle probe (docs/untracked/phase-33/midi/oracle-probe.md); write_abc re-emits ALL preserved directives verbatim; policy doc.','2026-06-12 07:31:41');
INSERT INTO "phase" VALUES('phase-35-ledger-burndown','codex/phase-35-ledger-burndown','merged',71,'https://github.com/ro-ag/croma/pull/71','4ff61de95d15fa4c79632a98eedb7ab0f31020f6','Pre-publish ledger burn-down: stale phase-33 recheck plus multirest MusicXML encoding publish blocker','Parser/export hardening (confirmed ledger bugs)','Closed phase-33 tracker bookkeeping; re-verified stale OPEN ledger entries fixed on main; fixed the multirest family by expanding ABC Zn/Xn into real full-measure rest measures in known meter and emitting MusicXML multiple-rest display metadata on visible Zn. Full 10k compare against phase-33 b8: matches 8858->8861, mismatch rows 167943->164267, zero match-to-mismatch regressions; round-trip remains 99.25 pct / 0 structural diffs.','Continue remaining OPEN ledger bugs: accidental trio, barline final on empty voice, decoration fallback, quoted volta text, lyric trio, complex meter time, nospace-key, octave pair, trailing grace/unclosed-chord recovery, slur grace/numbering, one-note tuplets.','2026-06-12 08:23:07');
INSERT INTO "phase" VALUES('phase-36-ledger-burndown','work/phase-36-ledger-burndown','complete',NULL,NULL,NULL,'tuplet-one-note-group-dangling-start','Parser/export hardening (confirmed ledger bug)','Fixed explicit one-note ABC tuplets such as (3:2:1G by attaching both TupletRole::Start and TupletRole::Stop to the same timed event. Targeted repros tune_010459/tune_010462 now export balanced one-note tuplet notation; residual target rows are abc2xml/music21 stop-only/null artifacts, not dangling Croma starts. Full 10k report-only compare: matches 8861, mismatch rows 164265, tuplet rows 607, zero MusicXML import failures.','Continue remaining OPEN ledger bugs with small confirmed repro=True targets first, especially extra-decoration-words-fallback, then barline-final-dropped-on-empty-voice-measure, quoted-volta text, complex-meter time, nospace-key, accidental trio, octave pair, lyric trio, trailing grace/unclosed-chord recovery, and slur grace/numbering.','2026-06-12 08:25:52');
INSERT INTO "phase" VALUES('phase-37-ledger-burndown','work/phase-37-ledger-burndown','complete',73,'https://github.com/ro-ag/croma/pull/73',NULL,'extra-decoration-words-fallback; barline-final-dropped-on-empty-voice-measure; measure-alignment-complex-meter-time-dropped; missing-nospace-key-global-accidentals-misparse; pitch-trailing-grace-group-dropped; pitch-unclosed-chord-recovery-drops-notes; slur-grace-group-slurs-dropped; slur-number-collision-shared-part; extra-abc2xml-drops-text-and-second-staff-dynamics (re-verdict); harmony-quoted-in-unterminated-bracket; accidental-grace-ledger-isolation; accidental-tie-carry-pollutes-next-bar; accidental-late-voice-key-seed; lyric-bar-advance-blind-to-rest-only-measures; lyric-liberal-barline-bracket-pair-note-drop (re-verdict); lyric-voice-overlay-syllable-matching; octave-staves-order-ignored; octave-midtune-clef-octave-shift-dropped; tuplet-fabricated-time-modification-for-inexpressible-durations; tuplet-nested-tuplets (re-verdict)','MusicXML export hardening (confirmed ledger bugs)','37a fixed supported decoration fallback export; 37b fixed empty-voice final barline preservation; 37c fixed complex/additive meter lowering and MusicXML time export; 37d preserved valid base keys for compact malformed key tokens; 37e preserved trailing trill grace groups as after-graces; 37f recovered top-level unclosed chord members before barlines while preventing grace-internal leaks; 37g preserved grace-internal slurs such as {(fg)}a2, with malformed grace slur diagnostics and no orphan MusicXML pairs; 37h allocated part-scoped MusicXML slur numbers for simultaneous voices in shared parts while preserving high pair ids; 37i re-verdicted extra-abc2xml-drops-text-and-second-staff-dynamics as not a Croma bug; 37j parsed quoted text repeat-bracket extensions such as ["cont" as text volta labels while preserving following harmonies and valid MusicXML ending numbers. Full 10k compare vs phase-36: structural matches 8861->8878, mismatch rows 164265->162455, accidental -55, barline -12, direction -4, duration -94, extra_in_croma -424, lyric -63, measure_alignment -73, missing_in_croma -936, octave -25, pitch -94, slur -4, voice -26; no harness/import/worker failures. ABC round-trip remains 99.25 pct in-scope with 0 structural diffs. 37k fixed accidental-grace-ledger-isolation by lowering grace notes through the measure accidental ledger, and fixed accidental-tie-carry-pollutes-next-bar by consuming synthetic tie carries after the stop note resolves. Target compares: grace 4/4 structural matches and tie 2/2 structural matches, both with 0 mismatch rows and no import/harness/worker failures. 37l fixed accidental-late-voice-key-seed by scoping standalone body K:/M: changes to the current voice timeline and seeding later voices from header key/meter until their own change. Target compare for tune_010949/tune_012206 is 2 structural matches, 0 mismatch rows, and no import/harness/worker failures. 37m fixed lyric-bar-advance-blind-to-rest-only-measures by using a measure-aware bar-marker cursor for lyric/symbol alignment. tune_013577 target compare improved 40 lyric rows with 26 lyric-count diagnostics to 1 unrelated empty-extender row and 0 diagnostics. 37n re-verdicted lyric-liberal-barline-bracket-pair-note-drop as stale/resolved: 3/4 original target files now structurally match and tune_012962 residual rows start from a reference-only zero-duration grace before the disputed bracket barline, not from a current dropped-note Croma bug. 37o fixed lyric-voice-overlay-syllable-matching by including overlay events in lyric/symbol alignment refs and attaching through main-or-overlay event paths. tune_006565 target compare improved 11->2 rows, clearing all lyric rows; the remaining two rows are measure-number-only alignment residuals. 37p fixed octave-staves-order-ignored by honoring explicit %%staves/%%score singleton ordering; tune_013106 target compare is clean. 37q fixed octave-midtune-clef-octave-shift-dropped with position-aware ClefChange events and mid-tune MusicXML clef attributes; tune_006650 target compare is clean. 37r fixed the remaining fabricated tuplets on inexpressible full-measure rests by omitting invented type/time-modification; tune_006472 target compare is clean. 37s re-verdicted tuplet-nested-tuplets as the existing dedicated nested-tuplet model/export backlog item. Fresh tune_003732 target compare remains 61 rows with 6 tuplet rows concentrated in measure 5 plus malformed-feature cascades; no narrow phase-37 fix was attempted. Final 37s full 10k export/report-only compare: 10000 attempted, 9935 Croma exports, 65 expected no_music failures, 0 import/harness/worker failures, structural matches 8898, mismatch rows 161873. Versus phase 36 this is +37 structural matches and -2392 rows; versus the 37j full report this is +20 matches and -582 rows.','Open PR/merge phase 37 when ready. Next technical backlog item is dedicated nested tuplets model/export support from docs/parser-backlog.md.','2026-06-12 16:21:33');
INSERT INTO "phase" VALUES('phase-38-empty-backlog','codex/phase-38-empty-backlog','complete',NULL,NULL,NULL,'Empty active parser/model/export backlog from docs/parser-backlog.md: nested tuplets; bare-grace slurs; overlay voice numbering; lyric syllabic; +: lyric continuation; orphan hyphens; stale OPEN ledger cleanup.','parser-model-export-backlog-elimination','Fixed nested tuplet model/export, bare-grace slur lowering/writer roundtrip, overlay MusicXML voice numbering, lyric continuation/syllabic/orphan-hyphen behavior, lyric syllabic comparison facts, and overlay lyric/symbol ABC writer alignment. Re-verdicted nested-tuplet target residuals as malformed/reference divergences. Backlog docs now mark active parser/model/export bugs empty. Final full 10k compare: 9935 exports, 8898 structural matches, 1037 structural mismatches, 161725 mismatch rows; ABC roundtrip: 9933 in-scope, 0 structural diffs.','No active parser/model/export backlog remains. Next work should be new evidence-driven parser reports or the previously deferred MusicXML->Score reader epic; formatter/LSP remain gated until explicitly opened.','2026-06-12 18:49:30');
INSERT INTO "phase" VALUES('phase-39-corpus-mismatch-burndown','codex/phase-39-corpus-mismatch-burndown','complete',NULL,NULL,NULL,'Fresh phase-39 evidence after phase-38 empty backlog; barline-only mismatch slice from 389 baseline single-category files, especially repeat barline styles and repeat-ending stops before new repeat starts.','MusicXML export hardening (repeat barline style and ending-stop boundaries)','Fixed explicit MusicXML bar-style for repeat-start/end/both and closed open repeat endings before trailing or next leading repeat starts. Fresh baseline: 9935 exports, 8898 matches, 161725 rows. Final full 10k compare: 9935 exports, 9187 matches, 748 mismatches, 160504 rows, barline rows 3533->2313, no import/harness/worker failures. Targeted 389 barline-only files improved to 288 matches, 101 residual mismatches, and 202 rows. Residual split/adjacent plain barline differences remain reference/comparator policy; repeat-ending residuals deferred for a broader repeat-ending target.','Next recommended target: missing default 4/4 meter export when no M: appears before first music; then repeat-ending framing for mid-measure [1/[2 forms.','2026-06-12 19:44:41');
INSERT INTO "phase" VALUES('phase-40-mismatch-followups','codex/phase-40-mismatch-followups','complete',NULL,NULL,NULL,'Phase-39 follow-ups after user-requested continuation: re-verify default-meter candidate, fix valid mid-measure repeat-ending [1/[2 framing, and recheck tie residuals.','Lowering/MusicXML export hardening (mid-measure repeat-ending pickup measures); default-meter candidate rejected as reference quirk.','Fixed mid-measure repeat endings by inserting an implicit regular boundary before [1/[2 when timed music already exists in the current measure. Targeted compact-ending files improved 0 matches/3 mismatches/5220 rows -> 3 matches/0 mismatches/0 rows. Corrected full 10k compare vs phase-39 final: 9935 exports, matches 9187->9206, mismatches 748->729, mismatch rows 160504->145986, no import/harness/worker failures, no match-to-mismatch regressions. Rejected synthetic default 4/4 for omitted M: after confirming ABC 2.1/2.2 free-meter semantics.','Start from current residual per-file/component evidence and first prove Croma-side fault; do not pursue default 4/4 for omitted M: unless the project explicitly chooses abc2xml compatibility over ABC free-meter semantics.','2026-06-12 21:43:11');
INSERT INTO "phase" VALUES('phase-41-residual-burndown','codex/phase-41-residual-burndown','complete',NULL,NULL,NULL,'Residual direction boundary placement from phase-40 per-file/component evidence: annotations and direction-style decorations immediately before barlines.','Lowering/MusicXML export hardening; Croma-side placement bug fixed for barline-bound annotations and direction-style decorations.','Fixed boundary placement for _quoted annotations and direction-style decorations before barlines by flushing them to a zero-duration timed anchor before lowering the barline. Targeted 257 direction-mismatch files: mismatch rows 86260->50440, direction-component rows 605->457, direction-component files 257->168. Clean phase-40 direction-only slice: 57 files/76 rows -> 40 files/50 rows, 17 structural matches. Full 10k compare: 9935 exports, matches 9206->9223, mismatches 729->712, mismatch rows 145986->109807, direction rows 451->304, no import/harness/worker failures.','Start from the phase-41 full 10k residual report. Remaining direction rows are mostly text-only Q: tempo policy, chord-symbol/harmony barline placement differences, and positional cascades; prove Croma-side fault before coding. Best next target is the largest remaining single-category slice after filtering documented reference quirks, not another default-meter compatibility change.','2026-06-12 23:55:52');
INSERT INTO "phase" VALUES('phase-42-residual-burndown','codex/phase-42-residual-burndown','complete',NULL,NULL,NULL,'Residual direction placement from phase-41 evidence: unprefixed quoted text that is not likely harmony immediately before non-final barlines.','Lowering/MusicXML export hardening; Croma-side placement bug fixed for non-harmony unprefixed quoted text before barlines.','Fixed non-harmony unprefixed quoted text before non-final barlines by flushing it to the current measure barline anchor while preserving valid chord-symbol next-note binding and final-barline dangling diagnostics. Focused 39-file direction target: 0->9 matches, rows 48->36. Broader 168-file direction target: 0->12 matches, rows 49888->46570, direction rows 304->284. Full 10k compare: 9935 exports, matches 9223->9237, mismatches 712->698, mismatch rows 109807->101106, no import/harness/worker failures and no match-to-mismatch regressions.','Start from the phase-42 full 10k residual tables. Do not chase tune_003837 phantom-measure rows as a Croma bug. Next target should be the largest clean residual slice after filtering reference-policy families, likely remaining text-only Q: tempo policy rows, malformed-input recovery with proven source preservation loss, or another single-category Croma-side repro.','2026-06-13 02:16:32');
INSERT INTO "phase" VALUES('phase-43-residual-burndown','codex/phase-43-residual-burndown','complete',NULL,NULL,NULL,'Phase-42 residual text-only Q: playback-only tempo rows surfaced by music21 as differing default BPM MetronomeMark text.','Comparison-policy hardening; documented text-only tempo playback defaults normalized without changing Croma export behavior.','Normalized music21 playback-only MetronomeMark direction facts so string-only Q: default BPM differences no longer count as Croma structural mismatches. Also fixed baseline JSONL mismatch-count loading for sparse typed columns. Targeted 26-file playback-only tempo slice: rows 515->489, direction rows 26->0, structural matches 0->24. Full 10k compare: matches 9237->9261, mismatches 698->674, mismatch rows 101106->101080, direction category rows 284->258, no regressions in baseline delta.','Start from docs/untracked/phase-43-residual-burndown/full-10k-mismatches.parquet and the phase-43 full report. Text-only Q: playback-only BPM rows are cleared. Remaining direction rows are malformed-input recovery, source-text preservation, harmony/chord-symbol placement policy, and positional cascades; continue only with evidence of a Croma-side parser/export fault, not abc2xml policy or music21 playback-default differences.','2026-06-13 02:41:22');
INSERT INTO "phase" VALUES('phase-44-residual-burndown','codex/phase-44-residual-burndown','complete',NULL,NULL,NULL,'Phase-43 residual tuplet rows where music21 actual/normal timing ratios match and only visible bracket start/stop type differs.','Comparison-policy hardening; documented tuplet bracket marker placement normalized without changing Croma export behavior.','Normalized tuplet comparison facts to ignore music21 bracket-marker type while preserving actual/normal timing ratio comparison. Targeted 12-file type-only tuplet slice: mismatch rows 1366->1325, tuplet category rows 93->52, structural matches 0->6. Full 10k compare: matches 9261->9267, mismatches 674->668, mismatch rows 101080->101039, tuplet category rows 318->277, no regressions in baseline delta.','Start from docs/untracked/phase-44-residual-burndown/full-10k-mismatches.parquet and the phase-44 full report. Tuplet bracket-marker placement rows are cleared. Remaining tuplet rows are not the same type-only family; continue with single-category slices only after proving either a Croma-side parser/export fault or a clearly non-structural comparison artifact.','2026-06-13 03:49:55');
INSERT INTO "phase" VALUES('phase-45-residual-burndown','codex/phase-45-residual-burndown','complete',NULL,NULL,NULL,'Phase-44 residual duration-only files where music21 rewrote an abc2xml full-measure rest to whole despite the next event offset proving a breve span.','Comparison-extractor hardening; documented full-measure rest duration extraction artifact normalized without changing Croma export behavior.','Corrected rest duration facts to use the next-event offset span only when music21 full-measure-rest handling shortens the reported duration. Targeted eight-file duration-only slice: mismatch rows 16->0 and structural matches 0->8. Full 10k compare: matches 9267->9275, mismatches 668->660, mismatch rows 101039->101023, duration category rows 13083->13067, no regressions.','Start from docs/untracked/phase-45-residual-burndown/full-10k-mismatches.parquet and the phase-45 full report. Full-measure-rest duration extractor artifacts are cleared. Remaining duration rows are not this family; continue with single-category slices only after proving either a Croma-side parser/export fault or a clearly non-structural comparison artifact.','2026-06-13 06:54:18');
INSERT INTO "phase" VALUES('phase-46-residual-burndown','codex/phase-46-residual-burndown','complete',NULL,NULL,NULL,'Phase-45 residual single-category barline files where visual-only barline style differences reflected documented abc2xml rendering policy rather than repeat semantics.','Comparison-policy hardening; visual-only barline style normalized while preserving repeat direction and repeat-ending span semantics.','Normalized plain barline facts to repeat semantics only. Targeted 183-file barline-only slice: mismatch rows 437->185 and structural matches 0->108. Full 10k compare: matches 9275->9383, mismatches 660->552, mismatch rows 101023->100394, barline category rows 1460->831, no regressions.','Start from docs/untracked/phase-46-residual-burndown/full-10k-mismatches.parquet and the phase-46 full report. Visual-only plain barline style rows are cleared. Remaining barline rows preserve repeat semantics or repeat-ending spans; continue with the largest clean single-category slice only after proving either a Croma-side parser/export fault or a clearly non-structural comparison artifact.','2026-06-13 07:06:33');
INSERT INTO "phase" VALUES('phase-47-residual-burndown','codex/phase-47-residual-burndown','complete',NULL,NULL,NULL,'Phase-46 residual files where the abc2xml reference starts a part with a zero-note harmony-only phantom measure while Croma''s corresponding first measure has notes.','Comparison-extractor hardening: pair-aware normalization of reference-side leading harmony phantom measures without changing Croma export behavior.','Normalized pair-aware reference leading harmony-only phantom measures and remapped retained/context measure numbers. Targeted 23-file slice: mismatch rows 20,774->13,669 and structural matches 0->3. Full 10k: structural matches 9,383->9,411, mismatches 552->524, mismatch rows 100,394->92,745, measure_alignment rows 7,232->6,433, harmony rows 1,211->901, with no file-level regressions.','Start from the phase-47 full 10k residual report. Do not generalize phantom-measure skipping beyond the pair-aware reference-leading harmony artifact; remaining candidates include bar/duration-only residual families, direction source-preservation rows, harmony placement policy, accidental grace-scope edges, and other clean single-category slices after proving Croma-side fault or a clearly non-structural comparison artifact.','2026-06-13 07:37:49');
INSERT INTO "phase" VALUES('phase-48-divergence-triage','codex/phase-48-divergence-triage','complete',NULL,NULL,NULL,'TRIAGE.md-driven croma-vs-abc2xml worklist batch: remaining lyric single-category files, then smallest duration/measure-alignment files.','parser-fix-and-drop-triage','Dispatched one fresh investigator per file for 9 candidates. Fixed Croma lyric syllabic export for trailing lyric hyphens, graduating tune_002758/tune_008447/tune_011626/tune_011627 to the whitelist. Added four reasoned duration drops for abc2xml duration-grid/broken-rhythm/equivalence artifacts. Kept tune_015465 because its overlapping chained broken-rhythm verdict was low-confidence undetermined.','Continue from docs/untracked/phase-48-divergence-triage/full-10k/mismatches-after-drops.parquet and report-after-drops.json. Keep tune_015465 unless a human policy decision resolves overlapping chained broken-rhythm semantics. Next clean duration/measure-alignment candidates are tune_009575, tune_010143, tune_009683, and tune_009684; dispatch one fresh investigator per file and do not bulk-drop structural cascades.','2026-06-14 02:22:15');
INSERT INTO "phase" VALUES('phase-49-divergence-triage','codex/phase-49-divergence-triage','complete',NULL,NULL,NULL,'TRIAGE.md-driven croma-vs-abc2xml worklist batch: first remaining octave-containing files from the phase-48 post-drop report.','triage-drop-batch','Investigated four octave-priority files with one fresh investigator per file, plus a refutation investigator for medium-confidence tune_012962. Dropped tune_014161 and tune_006602 as boundary-grace equivalences, and tune_007395 as an abc2xml pre-K phantom. Kept tune_012962 after refutation returned undetermined/low. No parser changes. Post-drop comparison: structural_matches=9264, structural_mismatches=550, dropped_files=121, mismatch_rows=42587.','Continue from docs/untracked/phase-49-divergence-triage/full-10k/mismatches-after-drops.parquet and report-after-drops.json. In requested content order, continue octave-containing files; keep tune_012962 unless a human policy decision resolves boundary-grace measure-side placement. Next octave candidates: tune_012468, tune_011263, tune_006807, tune_001046, tune_005365, tune_010375, tune_012737. Dispatch one fresh investigator per file; use refutation passes for medium-confidence or large-row drops; do not bulk-drop structural cascades.','2026-06-14 03:01:38');
INSERT INTO "phase" VALUES('phase-50-divergence-triage','codex/phase-50-divergence-triage','complete',NULL,NULL,NULL,'TRIAGE.md-driven croma-vs-abc2xml worklist batch: octave candidates from the phase-49 post-drop report through tune_015346.','croma fix plus abc2xml/equivalence drops','Investigated 49 candidate files with one fresh abc-divergence-investigator per file. Added 48 reasoned dropped.csv rows and fixed the Croma line-leading colon after repeat-end phantom-measure bug from tune_015346, which also graduated tune_004759, tune_006295, and tune_015365 into the whitelist. Final post-fix report: structural_matches=9268, structural_mismatches=498, dropped_files=169, mismatch_rows=33893.','Continue from docs/untracked/phase-50-divergence-triage/full-10k/mismatches-after-fix-and-drops-final.parquet and report-after-fix-and-drops-final.json. In requested content-category order, continue octave-containing files; keep tune_012962 unless a human policy decision resolves boundary-grace measure-side placement. Next octave candidates excluding tune_012962: tune_011164, tune_014745, tune_006299, tune_014902, tune_010565, tune_005352, tune_011364. Dispatch one fresh investigator per file; do not bulk-drop structural cascades.','2026-06-14 04:08:13');
INSERT INTO "phase" VALUES('phase-51-divergence-triage','codex/phase-51-divergence-triage','complete',NULL,NULL,NULL,'TRIAGE.md-driven croma-vs-abc2xml worklist batch: octave candidates after phase 50 through tune_014930.','croma fix plus abc2xml drop triage','Investigated 13 octave-priority candidate files with one fresh abc-divergence-investigator per file. Added 11 reasoned dropped.csv rows for abc2xml phantom/dropped-music artifacts, kept tune_011164 because its verdict was undetermined/low and tied to the deferred empty-bar policy, and fixed the Croma line-leading bare-colon after section-final |] bug from tune_014930. The fix graduated tune_014930 into whitelist.csv. Final post-fix/drop report: structural_matches=9269, structural_mismatches=486, dropped_files=180, mismatch_rows=29606.','Continue from docs/untracked/phase-51-divergence-triage/full-10k/mismatches-after-fix-and-drops.parquet and report-after-fix-and-drops.json. In requested content-category order, continue octave-containing files; keep tune_012962 unless the boundary-grace policy is decided and keep tune_011164 unless the empty-bar collapse policy is decided. Next octave candidates excluding those keeps: tune_006885, tune_009630, tune_009633, tune_009303, tune_015129, tune_009539, tune_012505, tune_014464, tune_015513, tune_013524, tune_012533, tune_006667. Dispatch one fresh investigator per file; do not bulk-drop structural cascades.','2026-06-14 05:33:02');
INSERT INTO "phase" VALUES('phase-52-divergence-triage','codex/phase-52-divergence-triage','complete',NULL,NULL,NULL,'TRIAGE.md-driven croma-vs-abc2xml worklist batch: remaining octave-containing candidates after phase 51.','abc2xml drop triage','Investigated remaining non-deferred octave-priority candidate files with one fresh abc-divergence-investigator per file and refutation passes for high-confidence drops. Added 33 reasoned dropped.csv rows for abc2xml phantom-measure/dropped-music artifacts. Kept deferred policy calls out of scope: tune_012962 boundary-grace policy, tune_011164/tune_009630/tune_013148/tune_007120 empty-bar or harmony-only collapse policy. No Croma parser changes were made. Final post-drop report-after-drops-6: structural_matches=9269, structural_mismatches=453, dropped_files=213, mismatch_rows=13350; non-deferred octave candidates are cleared.','Continue from docs/untracked/phase-52-divergence-triage/full-10k/mismatches-after-drops-6.parquet and report-after-drops-6.json. In requested content-category order, octave is clear except deferred policy files. Move to pitch candidates first: tune_001026, tune_006422, tune_003733, tune_004086, tune_014656, tune_009832, tune_013237. Dispatch one fresh investigator per file; do not bulk-drop structural cascades; keep deferred empty-bar/whitespace-colon policy calls for a human.','2026-06-14 06:37:17');
INSERT INTO "phase" VALUES('phase-53-divergence-triage','codex/phase-53-divergence-triage','complete',NULL,NULL,NULL,'TRIAGE.md-driven croma-vs-abc2xml worklist batch: first pitch-containing candidates after phase 52.','croma fix plus abc2xml/equivalence drop triage','Investigated 7 pitch-priority candidate files with one fresh abc-divergence-investigator per file. Added 5 reasoned dropped.csv rows for abc2xml phantom-measure artifacts and one equivalence; kept tune_001026 as undetermined/low boundary-grace adjacency; fixed Croma detached pre-barline grace placement after a complete measure from tune_006422. Final post-fix/drop report: structural_matches=9270, structural_mismatches=447, dropped_files=218, mismatch_rows=12262.','Continue from docs/untracked/phase-53-divergence-triage/full-10k/mismatches-after-fix-and-drops.parquet and report-after-fix-and-drops.json. In requested content-category order, pitch remaining files are deferred policy/undetermined boundary cases: tune_001026 and tune_012962 boundary-grace placement; tune_009630/tune_011164/tune_013148/tune_007120 empty-bar or harmony-only collapse. Move to duration/measure-alignment candidates excluding deferred tune_015465: tune_009575, tune_010143, tune_009683, tune_009684, tune_001629, tune_004317, tune_005956. Dispatch one fresh investigator per file; do not bulk-drop structural cascades.','2026-06-14 07:02:47');
INSERT INTO "phase" VALUES('phase-54-divergence-triage','codex/phase-54-divergence-triage','complete',NULL,NULL,NULL,'TRIAGE.md-driven croma-vs-abc2xml worklist batch: finish pure measure_alignment category after duration/voice rows, with human-approved bulk verification for forced-4/4 bar-duration artifacts.','abc2xml/music21/equivalence drops; no croma parser changes','Added 129 dropped.csv rows and a TRIAGE.md note for the user-approved forced-4/4 bulk exception. Pure measure_alignment single-category queue is now empty. No parser/export changes were made; no re-export was needed. Final comparison: structural_matches=9270, structural_mismatches=318, dropped_files=347, mismatch_rows=5764.','Continue from docs/untracked/phase-54-divergence-triage/full-10k/mismatches-after-drops.parquet and report-after-drops.json. Remaining content-category files are known keeps/deferred policy calls: tune_015465/tune_009575/tune_009205/tune_009207/tune_012357 broken-rhythm policy, tune_001026/tune_012962 boundary-grace placement, tune_009630/tune_011164/tune_013148/tune_007120 empty-bar/harmony-only collapse, tune_005539 whitespace-colon, tune_011865 empty-bar policy. Pure measure_alignment is clear. Next structural candidates excluding known keeps: tune_014512, tune_015363, tune_015366, tune_002101, tune_002102, tune_002103. Dispatch one fresh investigator per file unless the user explicitly approves a narrow regex/XML-verified bulk exception.','2026-06-14 15:13:42');
INSERT INTO "phase" VALUES('phase-55-divergence-triage','codex/phase-55-divergence-triage','complete',NULL,NULL,NULL,'TRIAGE.md-driven abc2xml divergence worklist: finish remaining structural cascade candidates after content categories, one fresh investigator per file.','parser/export fixes plus abc2xml/music21 artifact drops','Finished requested current category. Fixed croma parser/export bugs for bare user-defined symbols, unsupported-decoration words, chained tied accidental carry, trailing final/repeat barline handling, empty slur pairs, direction-only invisible/initial barlines, and repeated header Q override. Added 422 dropped.csv adjudications total and advanced whitelist to 9331 raw matches.','Current category is done. Remaining worklist is known deferred policy/content keeps plus smaller single-category barline/direction/slur/tuplet/harmony rows; do not revisit empty-bar collapse or whitespace-colon without human decision.','2026-06-14 18:45:53');
INSERT INTO "phase" VALUES('phase-56-divergence-triage','bugfix/bare-number-tempo-suffix','complete',NULL,NULL,NULL,'barline','parser fixes plus abc2xml-barline-style artifact drops','Rebaselined post-#97 (worklist 110). Cleared content categories; triaged barline. Investigated ~69 files (one fresh abc-divergence-investigator each + 2 adversarial tie-breakers). Fixed 2 croma bugs (TDD, full-corpus re-export, 0 whitelist regressions): bare-number tempo Q:400./Q:320s now emit metronome (lower/tempo.rs parse_bare_tempo_bpm, ABC 2.1 section 10.1); [| now closes an Nth ending (musicxml/score.rs stops_repeat_ending_barline omitted BarlineKind::Initial, section 4.10). Dropped 61 files (abc2xml-barline-style / equivalence / abc2xml-drops-music). Resolved space-separated | | = two single bars (section 4.9, croma correct, abc2xml fabricates light-light) via spec + 2 tie-breakers, overruling 2 wrong croma-bug verdicts. Deferred barline cluster (Bug 19/22/24) and policy calls (Bug 20/21 K:^F, 8105). State: whitelist 9378 / dropped 509 / worklist 48.','Remaining ~39 un-triaged barline files (mostly abc2xml-artifact drops); then the deferred barline croma-bug cluster (Bug 19/22/24) as a focused TDD session.','2026-06-14 23:02:51');
INSERT INTO "phase" VALUES('phase-57-fmt-proven-feature','docs/fmt-ungate','complete',NULL,NULL,NULL,'Promote croma fmt + --auto-fix from gated-secondary to a proven, un-gated feature (parser quality proven: whitelist 9,390 / dropped 545 / worklist 0).','formatter','Formatter promoted to a proven, un-gated feature. PR #119: in-process corpus_proof asserts idempotence+losslessness over the 10k corpus reusing the real verify gates (10000 files / 0 violations) + fmt_first_demo locks the reject->repair->recover pipeline (Q:320s, Q:400.). PR #120: MidiDirectiveSpacing curation + a third gate Gate::DirectiveTokens (textual; %%MIDI is not rendered) collapsing internal whitespace in active col-0 %%MIDI arg regions (59 corpus files). docs/fmt-ungate: AGENTS.md gate -> LSP-only, new docs/formatter.md, memory + tracker updates, spec Part-3/4 corrections. Tier-2 fixes (RedundantTie, UnterminatedTempoQuote) skipped: 0x in corpus. Black-box prove_fmt_lossless.py independently agrees 0/0/0. Catalogue now 7 curations / 3 gates.','LSP is the remaining gated item (AGENTS.md) -- promote once it has comparable evidence. Any future fmt curation must keep corpus_proof at 10000/0.','2026-06-15 18:49:10');
INSERT INTO "phase" VALUES('phase-58-midi-program-channel','feature/midi-program-channel','merged',122,'https://github.com/ro-ag/croma/pull/122','146724b','Mission B Scope 1: forward-translate %%MIDI program/channel into MusicXML part-list instruments','feature/export','Per-voice %%MIDI program (+optional channel) and sibling %%MIDI channel projected to <part-list> <score-instrument>/<midi-instrument>: 1-based <midi-program> (GM+1), abc2xml GM name table, per-voice scoping (nearest preceding V:, header or body). Preserved_directives kept verbatim for round-trip/fmt; abc writer untouched. 6 TDD croma-core tests; workspace+clippy+fmt clean. Full 10k re-export+compare: 9390 matches, 0 mismatches; whitelist set-diff 0 regressions / 0 graduations (comparator extracts no instrument facts, so neutral by construction; verified vs abc2xml part-list by spot-check). fmt corpus proof 10k/0 intact; ABC round-trip bar unchanged. Policy: docs/midi-directives.md.','phase-58 Scope 2: %%MIDI transpose -> <attributes><transpose><chromatic> (the only comparator-visible %%MIDI translation, via sounding pitch); land in isolation, gate/defer any whitelist-moving file.','2026-06-16 05:18:30');
INSERT INTO "phase" VALUES('phase-58-midi-transpose','feature/midi-transpose','complete',NULL,NULL,NULL,'Mission B Scope 2: forward-translate %%MIDI transpose into MusicXML <attributes><transpose>','feature/export','Per-voice %%MIDI transpose <n> projected to <attributes><transpose><chromatic>n in the scoped part first measure (reuses project_voice_midi scoping); does not shift written pitch. ABC transpose= property keeps precedence. Voice/VoiceTimeline gain midi_transpose: Option<i16>; writer write_transpose_if_available falls back to it. 3 TDD croma-core tests (9 MIDI total); workspace+clippy+fmt clean. Full 10k re-export+compare: 9390 matches, 0 mismatches; whitelist set-diff 0 regressions / 0 graduations. Byte-identical <transpose> vs abc2xml spot-checked. fmt corpus proof 10k/0 intact; to_abc.rs untouched so ABC round-trip unaffected. FINDING: transpose is comparator-invisible too (music21 keeps written pitch; comparator never converts to sounding) - 56/60 transpose files were already whitelisted with croma emitting no <transpose>. So NO principled %%MIDI translation can graduate whitelist files; both scopes are output-fidelity features. Policy: docs/midi-directives.md.','Mission B forward-MIDI complete for program/channel/transpose. Remaining %%MIDI deferred (all comparator-invisible, fidelity-only): channel-only (no program), inline [I:MIDI]program (round-trip loss). Not mimicked (abc2xml-isms): mid-tune visible prog: words, drummap percussion. MusicXML->Score reader (import <midi-instrument>/<transpose> back) is a separate epic.','2026-06-16 05:18:31');
INSERT INTO "phase" VALUES('phase-58-midi-control-channel','feature/midi-control-channel','complete',NULL,NULL,NULL,'Full %%MIDI part-list: control CC7/CC10 -> volume/pan + standalone channel-only instruments','feature/export','Completes the part-list instrument projection: %%MIDI control 7 -> <midi-instrument><volume> (n/1.27), control 10 -> <pan> (n/127*180-90); standalone %%MIDI channel (no program) now emits an instrument with the part name as <instrument-name> (never abc2xml no-name filler). MidiInstrumentModel gains volume_cc/pan_cc + has_content(); write_part_instruments widened. 4 TDD croma-core tests (13 MIDI total); workspace 531 pass, clippy/fmt clean. Full 10k re-export+compare: 9390 matches, 0 mismatches; whitelist set-diff 0 regressions / 0 graduations (comparator-invisible like all %%MIDI score-translations). Byte-identical to abc2xml spot-checked (tune_003557 channel/program/volume). fmt corpus proof 10k/0 intact; to_abc.rs untouched.','Remaining %%MIDI: inline [I:MIDI=program N] (parser-side, fixes round-trip loss) = next branch feature/midi-inline-program. Not mimicked (abc2xml-isms): mid-tune visible prog: words, drummap percussion. MusicXML->Score reader = separate epic.','2026-06-16 06:11:21');
INSERT INTO "phase" VALUES('phase-58-midi-inline','feature/midi-inline-program','complete',NULL,NULL,NULL,'Full %%MIDI: translate inline [I: MIDI=program N] (and channel/control/transpose) like the line-start forms','feature/export','project_voice_midi now scans tune_music.lines for inline [I: MIDI=...] items and projects them through the same voice-scoped dispatch as line-start %%MIDI (unified, source-position-sorted, last-wins). Fixes the inline round-trip-loss gap (was dropped with inline_instruction_ignored). 3 TDD croma-core tests (16 MIDI total); workspace 534 pass, clippy/fmt clean. Full 10k re-export+compare: 9390 matches, 0 mismatches; whitelist set-diff 0 regressions / 0 graduations. Byte-identical to abc2xml spot-checked (tune_007210 viola/cello/contrabass/tremolo_strings, tune_013220 cello). fmt corpus proof 10k/0 intact; to_abc.rs + parse untouched.','Forward %%MIDI translation COMPLETE for all score-meaningful sub-directives with a MusicXML home (program/channel/control7-10/transpose, line-start + inline). Excluded by spec discipline (abc2xml-isms): mid-tune visible prog: words, drummap percussion. Open: MusicXML->Score reader epic (import midi-instrument/transpose back).','2026-06-16 06:20:14');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s1','feature/mxml-read-s1-skeleton','merged',126,'https://github.com/ro-ag/croma/pull/126','440e97c','MusicXML->Score reader S1 skeleton: score-partwise/parts/measures/notes/backup/forward','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Feature-gated read_musicxml entry point: walks score-partwise -> parts -> measures -> notes, with <backup>/<forward> time-cursor handling. Default build stays dependency-free (reader behind the musicxml-reader feature). Opens the XML->Score import epic (reverse of the export/writer path).','phase-59 S2: attributes (divisions/key/time/clef/transpose) into the Score model.','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s2','feature/mxml-read-s2-attributes','merged',127,'https://github.com/ro-ag/croma/pull/127','92a3d2c','MusicXML->Score reader S2 attributes: divisions/key/time/clef/transpose','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads <attributes>: divisions, key (fifths plus explicit accidentals), time signature, clef, and <transpose> mapped back to midi_transpose on the Score. Begins reconstructing per-part header state from XML.','phase-59 S3: part-list MIDI instruments (close the %%MIDI forward/reverse loop).','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s3','feature/mxml-read-s3-midi','merged',128,'https://github.com/ro-ag/croma/pull/128','61256db','MusicXML->Score reader S3: part-list MIDI instruments; close the %%MIDI loop','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads <part-list> <score-instrument>/<midi-instrument> back into Score MIDI directives, closing the forward/reverse %%MIDI loop established by phase-58. Float CC (volume/pan) round-trip stability proven.','phase-59 S4: notations (ties/slurs/tuplets/decorations).','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s4','feature/mxml-read-s4-notations','merged',129,'https://github.com/ro-ag/croma/pull/129','5dc3dd7','MusicXML->Score reader S4 notations: ties/slurs/tuplets/decorations','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads <notations>: ties, slurs, tuplets, and decorations (articulations/ornaments) into the Score. Beams confirmed writer-derived (recomputed on emit), so they are not imported.','phase-59 S5: directions (tempo/dynamics/wedge/coda/segno/words).','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s5a','feature/mxml-read-s5-directions','merged',130,'https://github.com/ro-ag/croma/pull/130','a05e269','MusicXML->Score reader S5a directions: tempo/dynamics/wedge/coda/segno/words','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads <direction> content: tempo (metronome), dynamics, wedge (cresc./dim. hairpins), coda, segno, and free-text words into the Score direction model.','phase-59 S5b: harmony chord symbols + lyrics.','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s5b','feature/mxml-read-s5b-harmony-lyrics','merged',131,'https://github.com/ro-ag/croma/pull/131','c015326','MusicXML->Score reader S5b: harmony chord symbols + lyrics','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads <harmony> chord symbols and <lyric> syllables (with syllabic/extend handling) back into the Score.','phase-59 S6a: barlines + repeats/endings.','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s6a','feature/mxml-read-s6a-barlines','merged',132,'https://github.com/ro-ag/croma/pull/132','d3c4788','MusicXML->Score reader S6a: barlines + repeats/endings','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads <barline> bar styles plus repeats and endings (volta brackets) into the Score. Broadened the reader corpus by +7373 files now parseable on the import side.','phase-59 S6b: mid-measure key/meter/clef changes.','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s6b','feature/mxml-read-s6b-midmeasure-attrs','merged',133,'https://github.com/ro-ag/croma/pull/133','eb27050','MusicXML->Score reader S6b: mid-measure key/meter/clef changes','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads mid-measure <attributes> changes (key, meter, clef appearing after notes within a measure) into the Score as in-measure change events.','phase-59 S6c: grace notes + chords.','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s6c','feature/mxml-read-s6c-grace-chords','merged',134,'https://github.com/ro-ag/croma/pull/134','20a8766','MusicXML->Score reader S6c: grace notes + chords','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads <grace> notes and <chord> note stacking into the Score (grace groups and simultaneous chord pitches).','phase-59 S6d: multi-voice (<backup>/<voice>) + multiple-rest.','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s6d','feature/mxml-read-s6d-multivoice','merged',135,'https://github.com/ro-ag/croma/pull/135','1481295','MusicXML->Score reader S6d: multi-voice (<backup>/<voice>) + multiple-rest','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Reads multi-voice measures via <backup>/<voice> into separate Score voices, and reconstructs <multiple-rest> spans.','phase-59 S6e: totality hardening + fuzz.','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-59-mxml-read-s6e','feature/mxml-read-s6e-hardening','merged',136,'https://github.com/ro-ag/croma/pull/136','77d412c','MusicXML->Score reader S6e: totality hardening + fuzz; clean ordering edge','New feature (MusicXML->Score reader epic; feature-gated, experimental)','Totality hardening plus fuzzing over croma''s own 10k exports and the abc2xml-reference 10k (0 panics), and closed a clean element-ordering edge case. EPIC METRIC: the MusicXML->Score reader round-trips 9915/9935 corpus files under strict XML re-emission idempotence (99.80%); feature-gated musicxml-reader (experimental, NOT promoted); default build is zero-dependency; forward proofs untouched (forward source byte-identical across the epic). Documented residual: 19 cross-channel annotation+harmony ordering files + 1 nested-21:16 tuplet spelling.','MusicXML->Score reader epic COMPLETE (S1..S6e, PRs #126-#136). Next reader work is promotion-after-evidence (graduate the musicxml-reader feature once it has comparable corpus evidence to the un-gated forward path), or closing the documented residual: 19 cross-channel annotation+harmony ordering files + 1 nested-21:16 tuplet spelling.','2026-06-16 19:48:28');
INSERT INTO "phase" VALUES('phase-60-mxml-read-promote-r2',NULL,'planned',NULL,NULL,NULL,'Read abc2xml-reference 10k -> Score -> re-export croma XML -> music21 semantic compare vs original; triage divergences; worklist->0','Reference-dialect parity (gated)',NULL,'R3: self-loop residual closeout','2026-06-16 22:51:21');
INSERT INTO "phase" VALUES('phase-60-mxml-read-promote',NULL,'in_progress',NULL,NULL,NULL,'Promotion epic: reference-dialect coverage + CLI surface + residual closeout + un-gate','Reader promotion (mirror formatter: corpus-proven -> un-gated)','DECIDE-FIRST decisions in docs/superpowers/specs/2026-06-16-musicxml-reader-promotion.md: promotion bar (self-loop 9915/9935 + totality + reference-dialect music21 parity worklist->0 at >=93.9pct forward floor + reader->ABC structural round-trip categorized); reverse verification reuses music21_polars_corpus_compare.py with croma re-export; CLI read/musicxml2abc feature-plumbed, R4 flips CLI-default while croma-core stays opt-in zero-dep; foreign scope abc2xml-ref primary + music21 corpus stretch.','R2: reference-dialect music21 parity','2026-06-16 22:51:46');
INSERT INTO "phase" VALUES('phase-60-mxml-read-promote-r1','feature/mxml-read-r1-cli','complete',NULL,NULL,NULL,'Expose reader via croma-cli (read/musicxml2abc), feature-plumbed no default dep; prove XML->Score->ABC structural round-trip','Reader CLI surface (gated)','R1 DONE: gated croma-cli read/musicxml2abc (default build zero-dep, neither command exposed). complete_score_for_abc (ABC-path-only) synthesizes voice.events barlines from measure structure, canonical-major K: display from fifths, renumbers tuplet pair_ids globally-unique-per-voice. Structural reader->ABC round-trip 9514/9933 in-scope (95.8pct); residual 419 categorized. XML idempotence held 9915/9935; --format xml pure inverse preserved; forward byte-identical.','R2: reverse driver + abc2xml-ref music21 parity','2026-06-16 22:51:47');
